#if defined(__GNUC__) || defined(__clang__)
#  define MYLITE_STORAGE_HOT_INLINE static inline __attribute__((always_inline))
#  define MYLITE_STORAGE_NOINLINE __attribute__((noinline))
#else
#  define MYLITE_STORAGE_HOT_INLINE static inline
#  define MYLITE_STORAGE_NOINLINE
#endif

#if defined(__BYTE_ORDER__) && defined(__ORDER_LITTLE_ENDIAN__) &&                                 \
    __BYTE_ORDER__ == __ORDER_LITTLE_ENDIAN__
#  define MYLITE_STORAGE_NATIVE_LITTLE_ENDIAN 1
#else
#  define MYLITE_STORAGE_NATIVE_LITTLE_ENDIAN 0
#endif

#if MYLITE_STORAGE_NATIVE_LITTLE_ENDIAN
_Static_assert(
    sizeof(unsigned long long) == sizeof(uint64_t),
    "native little-endian storage accessors require 64-bit unsigned long long"
);
#endif
_Static_assert(
    MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_HEADER_SIZE ==
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE,
    "maintained index roots reuse leaf cell helpers"
);
_Static_assert(
    MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_ROW_ID_OFFSET ==
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET,
    "maintained index roots reuse leaf row-id helpers"
);
_Static_assert(
    MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_KEY_OFFSET ==
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET,
    "maintained index roots reuse leaf key helpers"
);

enum {
    MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN =
        (MYLITE_STORAGE_FORMAT_PAGE_SIZE - MYLITE_STORAGE_FORMAT_INDEX_BRANCH_PAYLOAD_OFFSET) /
        (MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + 1U),
    MYLITE_STORAGE_INDEX_BRANCH_MAX_MAINTAINED_LEVEL =
        MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - 1U
};

