mylite_storage_result mylite_storage_append_row_with_index_entries(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    const unsigned char *row,
    size_t row_size,
    const mylite_storage_index_entry *index_entries,
    size_t index_entry_count,
    unsigned long long *out_row_id
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0' || row == NULL || row_size == 0U) {
        return MYLITE_STORAGE_MISUSE;
    }
    if (row_size > UINT32_MAX) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }
    if (out_row_id != NULL) {
        *out_row_id = 0ULL;
    }
    mylite_storage_result result = validate_index_entries(index_entries, index_entry_count);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_update_file_scope file_scope = {0};
    result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;
    mylite_storage_statement *active_file_statement = file_scope.active_statement;
    mylite_storage_statement *active_cache_statement =
        active_cache_statement_from_statement(active_file_statement);

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    mylite_storage_maintained_index_insert_plan maintained_index_plan;
    unsigned long long table_id = 0ULL;
    unsigned long long planned_row_page_id = 0ULL;
    int has_catalog = 0;
    init_maintained_index_insert_plan(&maintained_index_plan);
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        if (find_active_table_entry_cache_in_statement(
                active_cache_statement,
                &header,
                schema_name,
                table_name,
                &table_entry
            )) {
            table_id = table_entry.table_id;
        }
    }
    if (result == MYLITE_STORAGE_OK && table_id == 0ULL) {
        result = read_catalog_image(file, &header, &catalog);
        if (result == MYLITE_STORAGE_OK) {
            has_catalog = 1;
        }
    }
    if (result == MYLITE_STORAGE_OK && table_id == 0ULL) {
        result = find_table_record(&catalog, schema_name, table_name, &table_entry);
        if (result == MYLITE_STORAGE_OK) {
            store_active_table_entry_cache_in_statement(
                active_cache_statement,
                &header,
                schema_name,
                table_name,
                &table_entry
            );
        }
    }
    if (result == MYLITE_STORAGE_OK && table_id == 0ULL) {
        table_id = table_entry.table_id;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = predict_append_row_page_id(&header, row_size, &planned_row_page_id);
    }
    const int needs_maintained_root_planning =
        index_entry_count != 0U &&
        !table_index_roots_absent_in_statement(active_cache_statement, &header, table_id);
    if (result == MYLITE_STORAGE_OK && needs_maintained_root_planning && !has_catalog) {
        result = read_catalog_image(file, &header, &catalog);
        if (result == MYLITE_STORAGE_OK) {
            has_catalog = 1;
        }
    }
    if (result == MYLITE_STORAGE_OK && needs_maintained_root_planning) {
        result = plan_maintained_index_root_inserts(
            file,
            filename,
            &header,
            &catalog,
            table_id,
            schema_name,
            table_name,
            index_entries,
            index_entry_count,
            planned_row_page_id,
            &maintained_index_plan
        );
    }
    if (result == MYLITE_STORAGE_OK && has_catalog &&
        !catalog_has_index_root_for_table(&catalog, table_id)) {
        store_table_index_roots_absent_in_statement(active_cache_statement, &header, table_id);
    }
    mylite_storage_row_write_position position = {0};
    if (result == MYLITE_STORAGE_OK) {
        seed_active_live_row_id_cache(filename, &header, table_id);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal_for_statement_pages(
            file,
            filename,
            &header,
            0,
            active_file_statement,
            maintained_index_plan.protected_page_ids,
            maintained_index_plan.protected_page_count
        );
    }
    int used_inline_insert_pages = 0;
    unsigned long long final_next_page_id = 0ULL;
    if (result == MYLITE_STORAGE_OK) {
        result = write_inline_insert_pages(
            file,
            &header,
            table_id,
            row,
            row_size,
            index_entries,
            index_entry_count,
            maintained_index_plan.index_entry_changed,
            &position,
            &final_next_page_id,
            &used_inline_insert_pages
        );
    }
    if (result == MYLITE_STORAGE_OK && !used_inline_insert_pages) {
        result = write_row_payload_pages(file, &header, table_id, row, row_size, &position);
        if (result == MYLITE_STORAGE_OK) {
            final_next_page_id = position.next_page_id;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = write_maintained_index_root_inserts(
            file,
            &header,
            table_id,
            position.row_page_id,
            position.next_page_id,
            index_entries,
            &maintained_index_plan
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = write_branch_index_root_inserts(
            file,
            filename,
            &header,
            table_id,
            position.row_page_id,
            index_entries,
            &maintained_index_plan,
            &final_next_page_id
        );
    }
    if (result == MYLITE_STORAGE_OK && !used_inline_insert_pages) {
        result = write_index_entry_pages(
            file,
            &header,
            (mylite_storage_index_entry_write){
                .first_page_id = position.next_page_id,
                .table_id = table_id,
                .row_id = position.row_page_id,
                .index_entries = index_entries,
                .index_entry_count = index_entry_count,
                .index_entry_changed = maintained_index_plan.index_entry_changed,
            },
            &final_next_page_id
        );
    }
    if (result == MYLITE_STORAGE_OK && maintained_index_plan.overflow_root_page_count != 0U) {
        mylite_storage_header promotion_header = header;
        promotion_header.page_count = final_next_page_id;
        result = promote_maintained_index_root_overflow_branches(
            file,
            &promotion_header,
            table_id,
            &maintained_index_plan,
            &final_next_page_id
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        header.page_count = final_next_page_id;
        result = publish_header(file, &header);
        if (result == MYLITE_STORAGE_OK) {
            result = finish_write_journal(file, filename);
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        advance_branch_tail_overlay_caches_after_branch_insert(
            active_file_statement,
            table_id,
            index_entries,
            index_entry_count,
            &maintained_index_plan,
            header.page_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = append_active_exact_index_cache_entries(
            filename,
            table_id,
            position.row_page_id,
            index_entries,
            index_entry_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        (void)mark_active_validated_live_row(file, &header, table_id, position.row_page_id);
        append_active_live_row_id(filename, &header, table_id, position.row_page_id);
        retarget_durable_caches_after_table_mutation_in_statement(
            active_file_statement,
            filename,
            &header,
            table_id
        );
        update_branch_refold_entryset_caches_after_branch_insert(
            active_cache_statement_from_statement(active_file_statement),
            table_id,
            position.row_page_id,
            index_entries,
            index_entry_count,
            &maintained_index_plan
        );
    }

    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    clear_maintained_index_insert_plan(&maintained_index_plan);
    free_catalog_image(&catalog);
    if (result == MYLITE_STORAGE_OK && out_row_id != NULL) {
        *out_row_id = position.row_page_id;
    }
    return result;
}

static mylite_storage_result plan_maintained_index_root_inserts(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    const mylite_storage_index_entry *index_entries,
    size_t index_entry_count,
    unsigned long long row_id,
    mylite_storage_maintained_index_insert_plan *out_plan
) {
    init_maintained_index_insert_plan(out_plan);
    if (index_entry_count == 0U) {
        return MYLITE_STORAGE_OK;
    }
    if (index_entry_count > SIZE_MAX / sizeof(*out_plan->index_entry_changed)) {
        return MYLITE_STORAGE_FULL;
    }

    if (index_entry_count <= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        out_plan->index_entry_changed = out_plan->inline_index_entry_changed;
    } else {
        out_plan->index_entry_changed =
            (unsigned char *)malloc(index_entry_count * sizeof(*out_plan->index_entry_changed));
        if (out_plan->index_entry_changed == NULL) {
            return MYLITE_STORAGE_NOMEM;
        }
    }
    memset(out_plan->index_entry_changed, 1, index_entry_count);

    for (size_t i = 0U; i < index_entry_count; ++i) {
        mylite_storage_catalog_entry root_entry = {0};
        mylite_storage_result result = find_index_root_record(
            catalog,
            schema_name,
            table_name,
            table_id,
            index_entries[i].index_number,
            &root_entry
        );
        if (result == MYLITE_STORAGE_NOTFOUND) {
            continue;
        }
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (maintained_index_insert_plan_has_protected_page(
                out_plan,
                root_entry.definition_root_page
            )) {
            continue;
        }
        if (!is_addressable_page_id(header, root_entry.definition_root_page)) {
            return MYLITE_STORAGE_CORRUPT;
        }

        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_index_branch_page branch_page = {0};
        int used_active_branch_cache = 0;
        result = read_cached_active_index_branch_page(
            file,
            header,
            root_entry.definition_root_page,
            page,
            &branch_page,
            &used_active_branch_cache
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (used_active_branch_cache) {
            result = plan_branch_index_root_insert(
                file,
                filename,
                header,
                catalog,
                &branch_page,
                table_id,
                schema_name,
                table_name,
                root_entry.definition_root_page,
                index_entries + i,
                i,
                row_id,
                out_plan
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            continue;
        }

        result = read_page_at(file, root_entry.definition_root_page, header->page_size, page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (!is_maintained_index_root_page(page)) {
            if (!is_index_branch_page(page)) {
                continue;
            }
#ifdef MYLITE_STORAGE_TEST_HOOKS
            ++test_active_branch_page_plan_read_count;
#endif

            result = decode_index_branch_page(
                header,
                root_entry.definition_root_page,
                page,
                &branch_page
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            store_active_index_branch_page_for_file(
                file,
                root_entry.definition_root_page,
                page,
                &branch_page
            );
            result = plan_branch_index_root_insert(
                file,
                filename,
                header,
                catalog,
                &branch_page,
                table_id,
                schema_name,
                table_name,
                root_entry.definition_root_page,
                index_entries + i,
                i,
                row_id,
                out_plan
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            continue;
        }

        mylite_storage_maintained_index_root_page root_page = {0};
        result = decode_maintained_index_root_page(
            header,
            root_entry.definition_root_page,
            page,
            &root_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (root_page.table_id != table_id ||
            root_page.index_number != index_entries[i].index_number ||
            root_page.key_size != index_entries[i].key_size) {
            continue;
        }
        if (out_plan->protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
            return MYLITE_STORAGE_UNSUPPORTED;
        }
        if (root_page.entry_count >= maintained_index_root_entry_capacity(root_page.key_size)) {
            result = append_maintained_index_insert_plan_overflow_root(
                out_plan,
                root_entry.definition_root_page
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            continue;
        }

        result =
            append_maintained_index_insert_plan_entry(out_plan, i, root_entry.definition_root_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    if (out_plan->count == 0U && out_plan->branch_count == 0U &&
        out_plan->deep_branch_count == 0U) {
        if (out_plan->index_entry_changed != out_plan->inline_index_entry_changed) {
            free(out_plan->index_entry_changed);
        }
        out_plan->index_entry_changed = NULL;
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_insert_plan_entry(
    mylite_storage_maintained_index_insert_plan *plan,
    size_t entry_index,
    unsigned long long root_page_id
) {
    if (plan->entries == NULL) {
        plan->entries = plan->inline_entries;
        plan->capacity = MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES;
    }
    if (plan->count == plan->capacity) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    plan->entries[plan->count++] = (mylite_storage_maintained_index_insert){
        .entry_index = entry_index,
        .root_page_id = root_page_id,
    };
    mylite_storage_result result =
        append_maintained_index_insert_plan_protected_page(plan, root_page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    plan->index_entry_changed[entry_index] = 0U;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_insert_plan_branch_entry(
    mylite_storage_maintained_index_insert_plan *plan,
    size_t entry_index,
    unsigned long long root_page_id,
    unsigned long long child_branch_page_id,
    unsigned long long grandchild_branch_page_id,
    unsigned long long greatgrandchild_branch_page_id,
    unsigned long long leaf_page_id,
    int split_leaf,
    int split_root,
    int split_child_branch,
    int split_upper_branch,
    int refold_branch
) {
    if (plan->branch_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_OK;
    }

    size_t needed_pages = 0U;
    if (!maintained_index_insert_plan_has_protected_page(plan, root_page_id)) {
        ++needed_pages;
    }
    if (!refold_branch && !maintained_index_insert_plan_has_protected_page(plan, leaf_page_id)) {
        ++needed_pages;
    }
    if (child_branch_page_id != 0ULL &&
        !maintained_index_insert_plan_has_protected_page(plan, child_branch_page_id)) {
        ++needed_pages;
    }
    if (grandchild_branch_page_id != 0ULL &&
        !maintained_index_insert_plan_has_protected_page(plan, grandchild_branch_page_id)) {
        ++needed_pages;
    }
    if (greatgrandchild_branch_page_id != 0ULL &&
        !maintained_index_insert_plan_has_protected_page(plan, greatgrandchild_branch_page_id)) {
        ++needed_pages;
    }
    if (needed_pages >
        MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - plan->protected_page_count) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_result result =
        append_maintained_index_insert_plan_protected_page(plan, root_page_id);
    if (result == MYLITE_STORAGE_OK && child_branch_page_id != 0ULL) {
        result = append_maintained_index_insert_plan_protected_page(plan, child_branch_page_id);
    }
    if (result == MYLITE_STORAGE_OK && grandchild_branch_page_id != 0ULL) {
        result =
            append_maintained_index_insert_plan_protected_page(plan, grandchild_branch_page_id);
    }
    if (result == MYLITE_STORAGE_OK && greatgrandchild_branch_page_id != 0ULL) {
        result = append_maintained_index_insert_plan_protected_page(
            plan,
            greatgrandchild_branch_page_id
        );
    }
    if (result == MYLITE_STORAGE_OK && !refold_branch) {
        result = append_maintained_index_insert_plan_protected_page(plan, leaf_page_id);
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    plan->branch_entries[plan->branch_count++] = (mylite_storage_branch_index_insert){
        .entry_index = entry_index,
        .root_page_id = root_page_id,
        .child_branch_page_id = child_branch_page_id,
        .grandchild_branch_page_id = grandchild_branch_page_id,
        .greatgrandchild_branch_page_id = greatgrandchild_branch_page_id,
        .leaf_page_id = leaf_page_id,
        .split_leaf = split_leaf,
        .split_root = split_root,
        .split_child_branch = split_child_branch,
        .split_upper_branch = split_upper_branch,
        .refold_branch = refold_branch,
    };
    plan->index_entry_changed[entry_index] = 0U;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_insert_plan_refold_branch_entry(
    mylite_storage_maintained_index_insert_plan *plan,
    size_t entry_index,
    unsigned long long root_page_id,
    unsigned long long row_id,
    mylite_storage_index_entryset *refold_entryset
) {
    if (row_id == 0ULL || refold_entryset == NULL ||
        refold_entryset->size < sizeof(*refold_entryset) || refold_entryset->entry_count == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t previous_branch_count = plan->branch_count;
    mylite_storage_result result = append_maintained_index_insert_plan_branch_entry(
        plan,
        entry_index,
        root_page_id,
        0ULL,
        0ULL,
        0ULL,
        0ULL,
        0,
        0,
        0,
        0,
        1
    );
    if (result != MYLITE_STORAGE_OK || plan->branch_count == previous_branch_count) {
        return result;
    }

    mylite_storage_branch_index_insert *insert = plan->branch_entries + previous_branch_count;
    insert->refold_entryset = *refold_entryset;
    insert->refold_row_id = row_id;
    insert->has_refold_entryset = 1;
    *refold_entryset = (mylite_storage_index_entryset){
        .size = sizeof(*refold_entryset),
    };
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_insert_plan_branch_range_redistribution(
    mylite_storage_maintained_index_insert_plan *plan,
    size_t entry_index,
    unsigned long long root_page_id,
    size_t leaf_range_start_child_index,
    const unsigned long long *leaf_page_ids,
    size_t leaf_page_count
) {
    if (plan->branch_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES ||
        leaf_page_ids == NULL || leaf_page_count < 2U ||
        leaf_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_OK;
    }

    size_t needed_pages = 0U;
    if (!maintained_index_insert_plan_has_protected_page(plan, root_page_id)) {
        ++needed_pages;
    }
    for (size_t i = 0U; i < leaf_page_count; ++i) {
        if (leaf_page_ids[i] == 0ULL) {
            return MYLITE_STORAGE_OK;
        }
        for (size_t j = 0U; j < i; ++j) {
            if (leaf_page_ids[i] == leaf_page_ids[j]) {
                return MYLITE_STORAGE_OK;
            }
        }
        if (!maintained_index_insert_plan_has_protected_page(plan, leaf_page_ids[i])) {
            ++needed_pages;
        }
    }
    if (needed_pages >
        MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - plan->protected_page_count) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_result result =
        append_maintained_index_insert_plan_protected_page(plan, root_page_id);
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < leaf_page_count; ++i) {
        result = append_maintained_index_insert_plan_protected_page(plan, leaf_page_ids[i]);
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    plan->branch_entries[plan->branch_count++] = (mylite_storage_branch_index_insert){
        .entry_index = entry_index,
        .root_page_id = root_page_id,
        .leaf_page_id = leaf_page_ids[0],
        .leaf_range_start_child_index = leaf_range_start_child_index,
        .leaf_range_count = leaf_page_count,
        .redistribute_leaf_range = 1,
    };
    plan->index_entry_changed[entry_index] = 0U;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_insert_plan_deep_branch_entry(
    mylite_storage_maintained_index_insert_plan *plan,
    size_t entry_index,
    unsigned level,
    const unsigned long long *branch_page_ids,
    unsigned long long leaf_page_id,
    int split_leaf,
    int split_lower_branch,
    int split_child_branch,
    int split_upper_branch,
    int split_level_four_branch,
    int split_level_five_branch,
    int split_level_six_branch,
    int split_level_seven_branch,
    int split_level_eight_branch,
    int split_level_nine_branch,
    int split_level_ten_branch,
    int promote_level_five_root,
    int promote_level_six_root,
    int promote_level_seven_root,
    int promote_level_eight_root,
    int promote_level_nine_root,
    int promote_level_ten_root
) {
    if (level == 0U || level > MYLITE_STORAGE_INDEX_BRANCH_MAX_MAINTAINED_LEVEL ||
        branch_page_ids == NULL || leaf_page_id == 0ULL ||
        plan->deep_branch_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_OK;
    }

    size_t needed_pages = 0U;
    for (unsigned i = 0U; i < level; ++i) {
        if (branch_page_ids[i] == 0ULL) {
            return MYLITE_STORAGE_OK;
        }
        if (!maintained_index_insert_plan_has_protected_page(plan, branch_page_ids[i])) {
            ++needed_pages;
        }
    }
    if (!maintained_index_insert_plan_has_protected_page(plan, leaf_page_id)) {
        ++needed_pages;
    }
    if (needed_pages >
        MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - plan->protected_page_count) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_result result = MYLITE_STORAGE_OK;
    for (unsigned i = 0U; result == MYLITE_STORAGE_OK && i < level; ++i) {
        result = append_maintained_index_insert_plan_protected_page(plan, branch_page_ids[i]);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = append_maintained_index_insert_plan_protected_page(plan, leaf_page_id);
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_deep_branch_index_insert *insert =
        plan->deep_branch_entries + plan->deep_branch_count++;
    *insert = (mylite_storage_deep_branch_index_insert){
        .entry_index = entry_index,
        .level = level,
        .leaf_page_id = leaf_page_id,
        .split_leaf = split_leaf,
        .split_lower_branch = split_lower_branch,
        .split_child_branch = split_child_branch,
        .split_upper_branch = split_upper_branch,
        .split_level_four_branch = split_level_four_branch,
        .split_level_five_branch = split_level_five_branch,
        .split_level_six_branch = split_level_six_branch,
        .split_level_seven_branch = split_level_seven_branch,
        .split_level_eight_branch = split_level_eight_branch,
        .split_level_nine_branch = split_level_nine_branch,
        .split_level_ten_branch = split_level_ten_branch,
        .promote_level_five_root = promote_level_five_root,
        .promote_level_six_root = promote_level_six_root,
        .promote_level_seven_root = promote_level_seven_root,
        .promote_level_eight_root = promote_level_eight_root,
        .promote_level_nine_root = promote_level_nine_root,
        .promote_level_ten_root = promote_level_ten_root,
    };
    memcpy(insert->branch_page_ids, branch_page_ids, (size_t)level * sizeof(branch_page_ids[0]));
    plan->index_entry_changed[entry_index] = 0U;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_insert_plan_overflow_root(
    mylite_storage_maintained_index_insert_plan *plan,
    unsigned long long root_page_id
) {
    if (plan->overflow_root_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    mylite_storage_result result =
        append_maintained_index_insert_plan_protected_page(plan, root_page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    plan->overflow_root_page_ids[plan->overflow_root_page_count++] = root_page_id;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_insert_plan_protected_page(
    mylite_storage_maintained_index_insert_plan *plan,
    unsigned long long page_id
) {
    if (maintained_index_insert_plan_has_protected_page(plan, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (plan->protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    plan->protected_page_ids[plan->protected_page_count++] = page_id;
    return MYLITE_STORAGE_OK;
}

static int maintained_index_insert_plan_has_protected_page(
    const mylite_storage_maintained_index_insert_plan *plan,
    unsigned long long page_id
) {
    for (size_t i = 0U; i < plan->protected_page_count; ++i) {
        if (plan->protected_page_ids[i] == page_id) {
            return 1;
        }
    }
    return 0;
}

static void init_maintained_index_insert_plan(mylite_storage_maintained_index_insert_plan *plan) {
    plan->index_entry_changed = NULL;
    plan->entries = NULL;
    plan->count = 0U;
    plan->capacity = 0U;
    plan->branch_count = 0U;
    plan->deep_branch_count = 0U;
    plan->protected_page_count = 0U;
    plan->overflow_root_page_count = 0U;
}

static mylite_storage_result plan_branch_index_root_insert(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_catalog_image *catalog,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    unsigned long long root_page_id,
    const mylite_storage_index_entry *index_entry,
    size_t entry_index,
    unsigned long long row_id,
    mylite_storage_maintained_index_insert_plan *out_plan
) {
    if (branch_page->table_id != table_id) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (branch_page->entry_count == 0ULL ||
        branch_page->index_number != index_entry->index_number ||
        branch_page->key_size != index_entry->key_size) {
        return MYLITE_STORAGE_OK;
    }
    if (branch_page->level > 4U) {
        return plan_deep_branch_index_root_insert(
            file,
            filename,
            header,
            branch_page,
            table_id,
            root_page_id,
            index_entry,
            entry_index,
            row_id,
            out_plan
        );
    }
    if (branch_page->level == 4U) {
        return plan_level_four_branch_index_root_insert(
            file,
            header,
            branch_page,
            table_id,
            root_page_id,
            index_entry,
            entry_index,
            row_id,
            out_plan
        );
    }
    if (branch_page->level == 3U) {
        return plan_level_three_branch_index_root_insert(
            file,
            header,
            branch_page,
            table_id,
            root_page_id,
            index_entry,
            entry_index,
            row_id,
            out_plan
        );
    }
    if (branch_page->level == 2U) {
        return plan_level_two_branch_index_root_insert(
            file,
            header,
            branch_page,
            table_id,
            root_page_id,
            index_entry,
            entry_index,
            row_id,
            out_plan
        );
    }
    if (branch_page->level != 1U) {
        return MYLITE_STORAGE_OK;
    }

    unsigned long long child_page_id = 0ULL;
    mylite_storage_result result = find_index_branch_child_page(
        branch_page,
        index_entry->key,
        index_entry->key_size,
        row_id,
        &child_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        const size_t cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
        const unsigned char *cell =
            branch_page->payload + ((branch_page->child_count - 1U) * cell_size);
        child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        result = MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char child_page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    int used_active_leaf_cache = 0;
    result = read_cached_active_index_leaf_page(
        file,
        header,
        child_page_id,
        child_page,
        &leaf_page,
        &used_active_leaf_cache
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (!used_active_leaf_cache) {
        result = read_page_at(file, child_page_id, header->page_size, child_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

        result = decode_index_leaf_page(header, child_page_id, child_page, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        store_active_index_leaf_page_for_file(file, child_page_id, child_page, &leaf_page);
    }
    if (leaf_page.table_id != branch_page->table_id ||
        leaf_page.index_number != branch_page->index_number ||
        leaf_page.key_size != branch_page->key_size) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const size_t leaf_capacity = index_leaf_entry_capacity(leaf_page.key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_OK;
    }
    if (leaf_page.entry_count >= leaf_capacity) {
        if (branch_page->entry_count == ULLONG_MAX) {
            return MYLITE_STORAGE_OK;
        }
        size_t child_index = 0U;
        result = find_index_branch_child_offset(branch_page, child_page_id, &child_index);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        const unsigned long long current_branch_capacity =
            (unsigned long long)branch_page->child_count * (unsigned long long)leaf_capacity;
        const size_t branch_child_capacity = index_branch_child_capacity(branch_page->key_size);
        const int split_candidate = branch_page->child_count < branch_child_capacity;
        if (split_candidate && branch_page->entry_count + 1ULL <= current_branch_capacity) {
            int adjacent_redistribution_planned = 0;
            result = try_plan_branch_leaf_range_insert_redistribution(
                file,
                header,
                branch_page,
                table_id,
                root_page_id,
                index_entry,
                entry_index,
                child_index,
                &leaf_page,
                leaf_capacity,
                2U,
                out_plan,
                &adjacent_redistribution_planned
            );
            if (result != MYLITE_STORAGE_OK || adjacent_redistribution_planned) {
                return result;
            }
        }
        if (split_candidate) {
            int has_live_overlay = 0;
            result = index_branch_tail_has_live_overlay(
                file,
                header,
                table_id,
                index_entry->index_number,
                branch_page,
                &has_live_overlay
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            if (!has_live_overlay) {
                return append_maintained_index_insert_plan_branch_entry(
                    out_plan,
                    entry_index,
                    root_page_id,
                    0ULL,
                    0ULL,
                    0ULL,
                    child_page_id,
                    1,
                    0,
                    0,
                    0,
                    0
                );
            }
        }
        if (branch_page->entry_count + 1ULL <= current_branch_capacity) {
            int redistribution_planned = 0;
            result = try_plan_branch_leaf_range_insert_redistribution(
                file,
                header,
                branch_page,
                table_id,
                root_page_id,
                index_entry,
                entry_index,
                child_index,
                &leaf_page,
                leaf_capacity,
                MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - 1U,
                out_plan,
                &redistribution_planned
            );
            if (result != MYLITE_STORAGE_OK || redistribution_planned) {
                return result;
            }

            int refold_planned = 0;
            result = try_plan_branch_index_root_refold_insert(
                file,
                filename,
                header,
                catalog,
                table_id,
                schema_name,
                table_name,
                root_page_id,
                branch_page,
                index_entry,
                entry_index,
                row_id,
                out_plan,
                &refold_planned
            );
            if (result != MYLITE_STORAGE_OK || refold_planned) {
                return result;
            }
            return MYLITE_STORAGE_OK;
        }
        if (branch_page->child_count < branch_child_capacity &&
            branch_page->entry_count == current_branch_capacity) {
            int has_live_overlay = 0;
            result = index_branch_tail_has_live_overlay(
                file,
                header,
                table_id,
                index_entry->index_number,
                branch_page,
                &has_live_overlay
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            if (has_live_overlay) {
                int refold_planned = 0;
                result = try_plan_branch_index_root_refold_insert(
                    file,
                    filename,
                    header,
                    catalog,
                    table_id,
                    schema_name,
                    table_name,
                    root_page_id,
                    branch_page,
                    index_entry,
                    entry_index,
                    row_id,
                    out_plan,
                    &refold_planned
                );
                if (result != MYLITE_STORAGE_OK || refold_planned) {
                    return result;
                }
                return MYLITE_STORAGE_OK;
            }
            return append_maintained_index_insert_plan_branch_entry(
                out_plan,
                entry_index,
                root_page_id,
                0ULL,
                0ULL,
                0ULL,
                child_page_id,
                1,
                0,
                0,
                0,
                0
            );
        }
        if (branch_page->child_count == branch_child_capacity && branch_child_capacity >= 2U &&
            branch_child_capacity < MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN &&
            branch_page->entry_count == current_branch_capacity) {
            int has_live_overlay = 0;
            result = index_branch_tail_has_live_overlay(
                file,
                header,
                table_id,
                index_entry->index_number,
                branch_page,
                &has_live_overlay
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            if (!has_live_overlay) {
                return append_maintained_index_insert_plan_branch_entry(
                    out_plan,
                    entry_index,
                    root_page_id,
                    0ULL,
                    0ULL,
                    0ULL,
                    child_page_id,
                    1,
                    1,
                    0,
                    0,
                    0
                );
            }
        }
        return MYLITE_STORAGE_OK;
    }

    return append_maintained_index_insert_plan_branch_entry(
        out_plan,
        entry_index,
        root_page_id,
        0ULL,
        0ULL,
        0ULL,
        child_page_id,
        0,
        0,
        0,
        0,
        0
    );
}

static mylite_storage_result try_plan_branch_leaf_range_insert_redistribution(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned long long root_page_id,
    const mylite_storage_index_entry *index_entry,
    size_t entry_index,
    size_t child_index,
    const mylite_storage_index_leaf_page *leaf_page,
    size_t leaf_capacity,
    size_t max_leaf_count,
    mylite_storage_maintained_index_insert_plan *out_plan,
    int *out_planned
) {
    *out_planned = 0;
    int has_live_overlay = 0;
    mylite_storage_result result = index_branch_tail_has_live_overlay(
        file,
        header,
        table_id,
        index_entry->index_number,
        branch_page,
        &has_live_overlay
    );
    if (result != MYLITE_STORAGE_OK || has_live_overlay) {
        return result;
    }
    if (leaf_page->entry_count < leaf_capacity) {
        return MYLITE_STORAGE_OK;
    }
    if (max_leaf_count < 2U) {
        return MYLITE_STORAGE_OK;
    }
    if (max_leaf_count > MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - 1U) {
        max_leaf_count = MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - 1U;
    }

    const unsigned long long selected_leaf_page_id =
        index_branch_child_page_id_at(branch_page, child_index);
    if (selected_leaf_page_id == 0ULL) {
        return MYLITE_STORAGE_CORRUPT;
    }
    result = try_plan_branch_leaf_range_insert_redistribution_right(
        file,
        header,
        branch_page,
        table_id,
        root_page_id,
        index_entry,
        entry_index,
        child_index,
        selected_leaf_page_id,
        leaf_page->entry_count,
        leaf_capacity,
        max_leaf_count,
        out_plan,
        out_planned
    );
    if (result != MYLITE_STORAGE_OK || *out_planned) {
        return result;
    }
    return try_plan_branch_leaf_range_insert_redistribution_left(
        file,
        header,
        branch_page,
        table_id,
        root_page_id,
        index_entry,
        entry_index,
        child_index,
        selected_leaf_page_id,
        leaf_page->entry_count,
        leaf_capacity,
        max_leaf_count,
        out_plan,
        out_planned
    );
}

static mylite_storage_result try_plan_branch_leaf_range_insert_redistribution_right(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned long long root_page_id,
    const mylite_storage_index_entry *index_entry,
    size_t entry_index,
    size_t child_index,
    unsigned long long selected_leaf_page_id,
    unsigned long long selected_entry_count,
    size_t leaf_capacity,
    size_t max_leaf_count,
    mylite_storage_maintained_index_insert_plan *out_plan,
    int *out_planned
) {
    *out_planned = 0;
    unsigned long long leaf_page_ids[MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES] = {0};
    leaf_page_ids[0] = selected_leaf_page_id;
    unsigned long long entry_count = selected_entry_count;
    size_t leaf_page_count = 1U;
    int has_range_slack = 0;

    for (size_t range_end_child_index = child_index + 1U;
         range_end_child_index < branch_page->child_count && leaf_page_count < max_leaf_count;
         ++range_end_child_index) {
        unsigned long long leaf_page_id = 0ULL;
        unsigned long long leaf_entry_count = 0ULL;
        mylite_storage_result result = read_branch_leaf_range_plan_scan_leaf(
            file,
            header,
            branch_page,
            table_id,
            index_entry,
            range_end_child_index,
            leaf_capacity,
            &leaf_page_id,
            &leaf_entry_count
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (entry_count > ULLONG_MAX - leaf_entry_count) {
            return MYLITE_STORAGE_FULL;
        }
        entry_count += leaf_entry_count;
        if (leaf_entry_count < leaf_capacity) {
            has_range_slack = 1;
        }
        leaf_page_ids[leaf_page_count++] = leaf_page_id;
        result = append_branch_leaf_range_insert_redistribution_if_fit(
            out_plan,
            root_page_id,
            entry_index,
            child_index,
            leaf_page_ids,
            leaf_page_count,
            entry_count,
            has_range_slack,
            leaf_capacity,
            out_planned
        );
        if (result != MYLITE_STORAGE_OK || *out_planned) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result try_plan_branch_leaf_range_insert_redistribution_left(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned long long root_page_id,
    const mylite_storage_index_entry *index_entry,
    size_t entry_index,
    size_t child_index,
    unsigned long long selected_leaf_page_id,
    unsigned long long selected_entry_count,
    size_t leaf_capacity,
    size_t max_leaf_count,
    mylite_storage_maintained_index_insert_plan *out_plan,
    int *out_planned
) {
    *out_planned = 0;
    unsigned long long leaf_page_ids[MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES] = {0};
    leaf_page_ids[0] = selected_leaf_page_id;
    unsigned long long entry_count = selected_entry_count;
    size_t leaf_page_count = 1U;
    int has_range_slack = 0;

    for (size_t range_start_child_index = child_index;
         range_start_child_index > 0U && leaf_page_count < max_leaf_count;) {
        --range_start_child_index;
        unsigned long long leaf_page_id = 0ULL;
        unsigned long long leaf_entry_count = 0ULL;
        mylite_storage_result result = read_branch_leaf_range_plan_scan_leaf(
            file,
            header,
            branch_page,
            table_id,
            index_entry,
            range_start_child_index,
            leaf_capacity,
            &leaf_page_id,
            &leaf_entry_count
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (entry_count > ULLONG_MAX - leaf_entry_count) {
            return MYLITE_STORAGE_FULL;
        }
        entry_count += leaf_entry_count;
        if (leaf_entry_count < leaf_capacity) {
            has_range_slack = 1;
        }
        memmove(leaf_page_ids + 1U, leaf_page_ids, leaf_page_count * sizeof(leaf_page_ids[0]));
        leaf_page_ids[0] = leaf_page_id;
        ++leaf_page_count;
        result = append_branch_leaf_range_insert_redistribution_if_fit(
            out_plan,
            root_page_id,
            entry_index,
            range_start_child_index,
            leaf_page_ids,
            leaf_page_count,
            entry_count,
            has_range_slack,
            leaf_capacity,
            out_planned
        );
        if (result != MYLITE_STORAGE_OK || *out_planned) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result read_branch_leaf_range_plan_scan_leaf(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    const mylite_storage_index_entry *index_entry,
    size_t branch_child_index,
    size_t leaf_capacity,
    unsigned long long *out_leaf_page_id,
    unsigned long long *out_entry_count
) {
    const unsigned long long leaf_page_id =
        index_branch_child_page_id_at(branch_page, branch_child_index);
    unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    int used_active_leaf_cache = 0;
    mylite_storage_result result = read_cached_active_index_leaf_page(
        file,
        header,
        leaf_page_id,
        leaf_page_bytes,
        &leaf_page,
        &used_active_leaf_cache
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (!used_active_leaf_cache) {
        result = read_page_at(file, leaf_page_id, header->page_size, leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

#ifdef MYLITE_STORAGE_TEST_HOOKS
        ++test_branch_leaf_range_plan_read_count;
#endif

        result = decode_index_leaf_page(header, leaf_page_id, leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        store_active_index_leaf_page_for_file(file, leaf_page_id, leaf_page_bytes, &leaf_page);
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != index_entry->index_number ||
        leaf_page.key_size != index_entry->key_size || leaf_page.entry_count > leaf_capacity) {
        return MYLITE_STORAGE_CORRUPT;
    }

    *out_leaf_page_id = leaf_page_id;
    *out_entry_count = leaf_page.entry_count;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_branch_leaf_range_insert_redistribution_if_fit(
    mylite_storage_maintained_index_insert_plan *out_plan,
    unsigned long long root_page_id,
    size_t entry_index,
    size_t range_start_child_index,
    const unsigned long long *leaf_page_ids,
    size_t leaf_page_count,
    unsigned long long entry_count,
    int has_range_slack,
    size_t leaf_capacity,
    int *out_planned
) {
    *out_planned = 0;
    if (!has_range_slack || entry_count == ULLONG_MAX ||
        entry_count + 1ULL >
            (unsigned long long)leaf_page_count * (unsigned long long)leaf_capacity) {
        return MYLITE_STORAGE_OK;
    }

    const size_t branch_count_before = out_plan->branch_count;
    mylite_storage_result result = append_maintained_index_insert_plan_branch_range_redistribution(
        out_plan,
        entry_index,
        root_page_id,
        range_start_child_index,
        leaf_page_ids,
        leaf_page_count
    );
    if (result == MYLITE_STORAGE_OK) {
        *out_planned = out_plan->branch_count > branch_count_before;
    }
    return result;
}

static mylite_storage_result plan_level_two_branch_index_root_insert(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned long long root_page_id,
    const mylite_storage_index_entry *index_entry,
    size_t entry_index,
    unsigned long long row_id,
    mylite_storage_maintained_index_insert_plan *out_plan
) {
    if (branch_page->entry_count == ULLONG_MAX || branch_page->child_count == 0U) {
        return MYLITE_STORAGE_OK;
    }

    unsigned long long child_branch_page_id = 0ULL;
    mylite_storage_result result = find_index_branch_child_page(
        branch_page,
        index_entry->key,
        index_entry->key_size,
        row_id,
        &child_branch_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        const size_t cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
        const unsigned char *cell =
            branch_page->payload + ((branch_page->child_count - 1U) * cell_size);
        child_branch_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        result = MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    size_t child_branch_index = 0U;
    result = find_index_branch_child_offset(branch_page, child_branch_page_id, &child_branch_index);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char child_branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_branch_page child_branch_page = {0};
    int used_active_branch_cache = 0;
    result = read_cached_active_index_branch_page(
        file,
        header,
        child_branch_page_id,
        child_branch_page_bytes,
        &child_branch_page,
        &used_active_branch_cache
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (!used_active_branch_cache) {
        result =
            read_page_at(file, child_branch_page_id, header->page_size, child_branch_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

#ifdef MYLITE_STORAGE_TEST_HOOKS
        ++test_active_branch_page_plan_read_count;
#endif

        result = decode_index_branch_page(
            header,
            child_branch_page_id,
            child_branch_page_bytes,
            &child_branch_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        store_active_index_branch_page_for_file(
            file,
            child_branch_page_id,
            child_branch_page_bytes,
            &child_branch_page
        );
    }
    if (child_branch_page.table_id != table_id ||
        child_branch_page.index_number != index_entry->index_number ||
        child_branch_page.key_size != index_entry->key_size || child_branch_page.level != 1U ||
        child_branch_page.entry_count == 0ULL || child_branch_page.entry_count == ULLONG_MAX) {
        return MYLITE_STORAGE_CORRUPT;
    }
    result = validate_index_branch_child_branch_fence(
        branch_page,
        child_branch_index,
        &child_branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned long long leaf_page_id = 0ULL;
    result = find_index_branch_child_page(
        &child_branch_page,
        index_entry->key,
        index_entry->key_size,
        row_id,
        &leaf_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        const size_t cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + child_branch_page.key_size;
        const unsigned char *cell =
            child_branch_page.payload + ((child_branch_page.child_count - 1U) * cell_size);
        leaf_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        result = MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    int used_active_leaf_cache = 0;
    result = read_cached_active_index_leaf_page(
        file,
        header,
        leaf_page_id,
        leaf_page_bytes,
        &leaf_page,
        &used_active_leaf_cache
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (!used_active_leaf_cache) {
        result = read_page_at(file, leaf_page_id, header->page_size, leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

#ifdef MYLITE_STORAGE_TEST_HOOKS
        ++test_level_two_branch_leaf_plan_read_count;
#endif

        result = decode_index_leaf_page(header, leaf_page_id, leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        store_active_index_leaf_page_for_file(file, leaf_page_id, leaf_page_bytes, &leaf_page);
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != index_entry->index_number ||
        leaf_page.key_size != index_entry->key_size) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_capacity = index_leaf_entry_capacity(leaf_page.key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_OK;
    }
    if (leaf_page.entry_count >= leaf_capacity) {
        const size_t child_branch_capacity =
            index_branch_child_capacity(child_branch_page.key_size);
        const unsigned long long current_branch_capacity =
            (unsigned long long)child_branch_page.child_count * (unsigned long long)leaf_capacity;
        if (child_branch_page.entry_count != current_branch_capacity) {
            return MYLITE_STORAGE_OK;
        }

        int has_live_overlay = 0;
        result = index_branch_tail_has_live_overlay(
            file,
            header,
            table_id,
            index_entry->index_number,
            branch_page,
            &has_live_overlay
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (has_live_overlay) {
            return MYLITE_STORAGE_OK;
        }

        if (child_branch_page.child_count >= child_branch_capacity) {
            const size_t root_branch_capacity = index_branch_child_capacity(branch_page->key_size);
            if (child_branch_page.child_count != child_branch_capacity ||
                child_branch_capacity < 2U ||
                child_branch_capacity >= MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN ||
                (branch_page->child_count >= root_branch_capacity &&
                 (branch_page->child_count != root_branch_capacity || root_branch_capacity < 2U ||
                  root_branch_capacity >= MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN))) {
                return MYLITE_STORAGE_OK;
            }
            return append_maintained_index_insert_plan_branch_entry(
                out_plan,
                entry_index,
                root_page_id,
                child_branch_page_id,
                0ULL,
                0ULL,
                leaf_page_id,
                1,
                1,
                0,
                0,
                0
            );
        }

        return append_maintained_index_insert_plan_branch_entry(
            out_plan,
            entry_index,
            root_page_id,
            child_branch_page_id,
            0ULL,
            0ULL,
            leaf_page_id,
            1,
            0,
            0,
            0,
            0
        );
    }

    return append_maintained_index_insert_plan_branch_entry(
        out_plan,
        entry_index,
        root_page_id,
        child_branch_page_id,
        0ULL,
        0ULL,
        leaf_page_id,
        0,
        0,
        0,
        0,
        0
    );
}

static mylite_storage_result plan_level_three_branch_index_root_insert(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned long long root_page_id,
    const mylite_storage_index_entry *index_entry,
    size_t entry_index,
    unsigned long long row_id,
    mylite_storage_maintained_index_insert_plan *out_plan
) {
    if (branch_page->entry_count == ULLONG_MAX || branch_page->child_count == 0U) {
        return MYLITE_STORAGE_OK;
    }

    unsigned long long child_branch_page_id = 0ULL;
    mylite_storage_result result = find_index_branch_child_page(
        branch_page,
        index_entry->key,
        index_entry->key_size,
        row_id,
        &child_branch_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        const size_t cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
        const unsigned char *cell =
            branch_page->payload + ((branch_page->child_count - 1U) * cell_size);
        child_branch_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        result = MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    size_t child_branch_index = 0U;
    result = find_index_branch_child_offset(branch_page, child_branch_page_id, &child_branch_index);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char child_branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = read_page_at(file, child_branch_page_id, header->page_size, child_branch_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_branch_page child_branch_page = {0};
    result = decode_index_branch_page(
        header,
        child_branch_page_id,
        child_branch_page_bytes,
        &child_branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (child_branch_page.table_id != table_id ||
        child_branch_page.index_number != index_entry->index_number ||
        child_branch_page.key_size != index_entry->key_size || child_branch_page.level != 2U ||
        child_branch_page.entry_count == 0ULL || child_branch_page.entry_count == ULLONG_MAX) {
        return MYLITE_STORAGE_CORRUPT;
    }
    result = validate_index_branch_child_branch_fence(
        branch_page,
        child_branch_index,
        &child_branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned long long lower_branch_page_id = 0ULL;
    result = find_index_branch_child_page(
        &child_branch_page,
        index_entry->key,
        index_entry->key_size,
        row_id,
        &lower_branch_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        const size_t cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + child_branch_page.key_size;
        const unsigned char *cell =
            child_branch_page.payload + ((child_branch_page.child_count - 1U) * cell_size);
        lower_branch_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        result = MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    size_t lower_branch_index = 0U;
    result = find_index_branch_child_offset(
        &child_branch_page,
        lower_branch_page_id,
        &lower_branch_index
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char lower_branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = read_page_at(file, lower_branch_page_id, header->page_size, lower_branch_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_branch_page lower_branch_page = {0};
    result = decode_index_branch_page(
        header,
        lower_branch_page_id,
        lower_branch_page_bytes,
        &lower_branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (lower_branch_page.table_id != table_id ||
        lower_branch_page.index_number != index_entry->index_number ||
        lower_branch_page.key_size != index_entry->key_size || lower_branch_page.level != 1U ||
        lower_branch_page.entry_count == 0ULL || lower_branch_page.entry_count == ULLONG_MAX) {
        return MYLITE_STORAGE_CORRUPT;
    }
    result = validate_index_branch_child_branch_fence(
        &child_branch_page,
        lower_branch_index,
        &lower_branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned long long leaf_page_id = 0ULL;
    result = find_index_branch_child_page(
        &lower_branch_page,
        index_entry->key,
        index_entry->key_size,
        row_id,
        &leaf_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        const size_t cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + lower_branch_page.key_size;
        const unsigned char *cell =
            lower_branch_page.payload + ((lower_branch_page.child_count - 1U) * cell_size);
        leaf_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        result = MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = read_page_at(file, leaf_page_id, header->page_size, leaf_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_leaf_page leaf_page = {0};
    result = decode_index_leaf_page(header, leaf_page_id, leaf_page_bytes, &leaf_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != index_entry->index_number ||
        leaf_page.key_size != index_entry->key_size) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_capacity = index_leaf_entry_capacity(leaf_page.key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_OK;
    }
    if (leaf_page.entry_count >= leaf_capacity) {
        const size_t lower_branch_capacity =
            index_branch_child_capacity(lower_branch_page.key_size);
        const unsigned long long current_branch_capacity =
            (unsigned long long)lower_branch_page.child_count * (unsigned long long)leaf_capacity;
        if (lower_branch_capacity == 0U ||
            lower_branch_capacity >= MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN ||
            lower_branch_page.entry_count != current_branch_capacity) {
            return MYLITE_STORAGE_OK;
        }
        if (lower_branch_page.child_count > lower_branch_capacity) {
            return MYLITE_STORAGE_OK;
        }

        const int split_lower_branch = lower_branch_page.child_count == lower_branch_capacity;
        int split_child_branch = 0;
        if (split_lower_branch) {
            const size_t child_branch_capacity =
                index_branch_child_capacity(child_branch_page.key_size);
            if (child_branch_capacity == 0U ||
                child_branch_capacity >= MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN ||
                child_branch_page.child_count > child_branch_capacity) {
                return MYLITE_STORAGE_OK;
            }
            split_child_branch = child_branch_page.child_count == child_branch_capacity;
            if (split_child_branch) {
                const size_t root_branch_capacity =
                    index_branch_child_capacity(branch_page->key_size);
                if (root_branch_capacity == 0U ||
                    root_branch_capacity >= MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN ||
                    branch_page->child_count > root_branch_capacity) {
                    return MYLITE_STORAGE_OK;
                }
            }
        }

        int has_live_overlay = 0;
        result = index_branch_tail_has_live_overlay(
            file,
            header,
            table_id,
            index_entry->index_number,
            branch_page,
            &has_live_overlay
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (has_live_overlay) {
            return MYLITE_STORAGE_OK;
        }

        return append_maintained_index_insert_plan_branch_entry(
            out_plan,
            entry_index,
            root_page_id,
            child_branch_page_id,
            lower_branch_page_id,
            0ULL,
            leaf_page_id,
            1,
            split_lower_branch,
            split_child_branch,
            0,
            0
        );
    }

    return append_maintained_index_insert_plan_branch_entry(
        out_plan,
        entry_index,
        root_page_id,
        child_branch_page_id,
        lower_branch_page_id,
        0ULL,
        leaf_page_id,
        0,
        0,
        0,
        0,
        0
    );
}

