static mylite_storage_result update_row_with_index_entries(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    unsigned long long row_id,
    const unsigned char *row,
    size_t row_size,
    const mylite_storage_index_entry *index_entries,
    size_t index_entry_count,
    const unsigned char *index_entry_changed,
    int preserve_index_entries,
    unsigned long long *out_new_row_id
) {
    return update_row_with_index_entries_for_context(
        NULL,
        filename,
        schema_name,
        table_name,
        row_id,
        row,
        row_size,
        index_entries,
        index_entry_count,
        index_entry_changed,
        preserve_index_entries,
        out_new_row_id
    );
}

static mylite_storage_result update_row_with_index_entries_in_statement(
    mylite_storage_statement *statement,
    const char *schema_name,
    const char *table_name,
    unsigned long long row_id,
    const unsigned char *row,
    size_t row_size,
    const mylite_storage_index_entry *index_entries,
    size_t index_entry_count,
    const unsigned char *index_entry_changed,
    int preserve_index_entries,
    unsigned long long *out_new_row_id
) {
    if (statement == NULL || statement->file == NULL || statement->filename == NULL ||
        statement->filename[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    return update_row_with_index_entries_for_context(
        statement,
        statement->filename,
        schema_name,
        table_name,
        row_id,
        row,
        row_size,
        index_entries,
        index_entry_count,
        index_entry_changed,
        preserve_index_entries,
        out_new_row_id
    );
}

static mylite_storage_result update_row_with_index_entries_for_context(
    mylite_storage_statement *statement,
    const char *filename,
    const char *schema_name,
    const char *table_name,
    unsigned long long row_id,
    const unsigned char *row,
    size_t row_size,
    const mylite_storage_index_entry *index_entries,
    size_t index_entry_count,
    const unsigned char *index_entry_changed,
    int preserve_index_entries,
    unsigned long long *out_new_row_id
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0' || row_id == 0ULL || row == NULL ||
        row_size == 0U || out_new_row_id == NULL) {
        return MYLITE_STORAGE_MISUSE;
    }
    if (preserve_index_entries &&
        (index_entries != NULL || index_entry_count != 0U || index_entry_changed != NULL)) {
        return MYLITE_STORAGE_MISUSE;
    }
    if (row_size > UINT32_MAX) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    *out_new_row_id = 0ULL;
    mylite_storage_result result = validate_index_entries(index_entries, index_entry_count);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_update_file_scope file_scope = {0};
    const int owns_update_file_scope = statement == NULL;
    if (statement != NULL) {
        file_scope.file = statement->file;
        file_scope.active_statement = statement;
    } else {
        result = open_existing_file_for_update_scope(filename, &file_scope);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    FILE *file = file_scope.file;
    mylite_storage_statement *active_file_statement = file_scope.active_statement;
    mylite_storage_statement *active_append_buffer_statement = NULL;
    mylite_storage_statement *active_cache_statement = NULL;
    active_cache_and_append_buffer_from_statement(
        active_file_statement,
        &active_cache_statement,
        &active_append_buffer_statement
    );

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_maintained_index_update_plan maintained_index_plan;
    mylite_storage_maintained_index_retarget_plan maintained_index_retarget_plan = {0};
    int has_maintained_index_plan = 0;
    int has_maintained_index_retarget_plan = 0;
    int has_catalog = 0;
    unsigned long long table_id = 0ULL;
    mylite_storage_row_page old_row_page = {0};
    mylite_storage_live_row_cache *active_live_row_cache = NULL;
    mylite_storage_row_payload_cache *active_row_payload_cache = NULL;
    mylite_storage_row_payload_cache_entry *active_row_payload_entry = NULL;
    mylite_storage_row_payload_cache_bucket *active_row_payload_bucket = NULL;
    unsigned char old_row_buffer[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_row_write_position position = {0};
    if (statement != NULL) {
        header = statement->has_current_header ? statement->current_header : statement->header;
    } else {
        result = read_header_from_update_file_scope(&file_scope, &header);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_id_in_statement(
            file,
            &header,
            active_cache_statement,
            schema_name,
            table_name,
            &table_id
        );
    }
    const int needs_maintained_root_planning =
        (index_entry_count != 0U || preserve_index_entries) &&
        !table_index_roots_absent_in_statement(active_cache_statement, &header, table_id);
    if (result == MYLITE_STORAGE_OK && needs_maintained_root_planning) {
        result = read_catalog_image(file, &header, &catalog);
        if (result == MYLITE_STORAGE_OK) {
            has_catalog = 1;
        }
    }
    if (result == MYLITE_STORAGE_OK && has_catalog && !preserve_index_entries) {
        has_maintained_index_plan = 1;
        result = plan_maintained_index_root_updates(
            file,
            &header,
            &catalog,
            table_id,
            schema_name,
            table_name,
            row_id,
            row_size,
            index_entries,
            index_entry_count,
            index_entry_changed,
            &maintained_index_plan
        );
    }
    if (result == MYLITE_STORAGE_OK && has_catalog) {
        const mylite_storage_maintained_index_update_plan *updated_roots =
            !preserve_index_entries && has_maintained_index_plan ? &maintained_index_plan : NULL;
        has_maintained_index_retarget_plan = 1;
        result = plan_maintained_index_root_retargets(
            file,
            &header,
            &catalog,
            table_id,
            schema_name,
            table_name,
            updated_roots,
            row_id,
            &maintained_index_retarget_plan
        );
    }
    if (result == MYLITE_STORAGE_OK && has_catalog &&
        !catalog_has_index_root_for_table(&catalog, table_id)) {
        store_table_index_roots_absent_in_statement(active_cache_statement, &header, table_id);
    }
    if (result == MYLITE_STORAGE_OK) {
        active_row_payload_cache = active_row_payload_cache_for_resolved_statement(
            active_cache_statement,
            &header,
            table_id
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = validate_direct_live_row_in_statement_cache(
            active_cache_statement,
            &active_live_row_cache,
            1,
            active_row_payload_cache,
            file,
            &header,
            table_id,
            row_id,
            old_row_buffer,
            &old_row_page,
            &active_row_payload_entry,
            &active_row_payload_bucket
        );
    }
    unsigned long long next_page_id = 0ULL;
    int used_inline_update_pages = 0;
    int used_active_update_rewrite = 0;
    const unsigned char *index_entry_write_changed =
        has_maintained_index_plan && maintained_index_plan.index_entry_changed != NULL
            ? maintained_index_plan.index_entry_changed
            : index_entry_changed;
    const int has_maintained_index_updates =
        has_maintained_index_plan && !maintained_index_update_plan_is_empty(&maintained_index_plan);
    const int has_maintained_index_retargets =
        has_maintained_index_retarget_plan &&
        !maintained_index_retarget_plan_is_empty(&maintained_index_retarget_plan);
    if (result == MYLITE_STORAGE_OK) {
        if (!has_maintained_index_updates && !has_maintained_index_retargets) {
            result = rewrite_active_update_pages(
                active_file_statement,
                active_append_buffer_statement,
                &header,
                table_id,
                row_id,
                row,
                row_size,
                index_entries,
                index_entry_count,
                index_entry_changed,
                &used_active_update_rewrite
            );
        }
        if (result == MYLITE_STORAGE_OK && used_active_update_rewrite) {
            position = (mylite_storage_row_write_position){
                .row_page_id = row_id,
                .next_page_id = header.page_count,
            };
            next_page_id = header.page_count;
        }
    }
    if (result == MYLITE_STORAGE_OK && !used_active_update_rewrite) {
        seed_active_live_row_id_cache_in_statement(
            active_cache_statement,
            filename,
            &header,
            table_id
        );
    }
    if (result == MYLITE_STORAGE_OK && !used_active_update_rewrite) {
        unsigned long long protected_pages[MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES];
        const unsigned long long *protected_page_ids = NULL;
        size_t protected_page_count = 0U;
        if (has_maintained_index_updates) {
            for (size_t i = 0U;
                 result == MYLITE_STORAGE_OK && i < maintained_index_plan.protected_page_count;
                 ++i) {
                const unsigned long long page_id = maintained_index_plan.protected_page_ids[i];
                int already_protected = 0;
                for (size_t j = 0U; j < protected_page_count; ++j) {
                    already_protected = already_protected || protected_pages[j] == page_id;
                }
                if (!already_protected) {
                    if (protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
                        result = MYLITE_STORAGE_UNSUPPORTED;
                    } else {
                        protected_pages[protected_page_count++] = page_id;
                    }
                }
            }
        }
        if (has_maintained_index_retargets) {
            for (size_t i = 0U; result == MYLITE_STORAGE_OK &&
                                i < maintained_index_retarget_plan.protected_page_count;
                 ++i) {
                const unsigned long long page_id =
                    maintained_index_retarget_plan.protected_page_ids[i];
                int already_protected = 0;
                for (size_t j = 0U; j < protected_page_count; ++j) {
                    already_protected = already_protected || protected_pages[j] == page_id;
                }
                if (!already_protected) {
                    if (protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
                        result = MYLITE_STORAGE_UNSUPPORTED;
                    } else {
                        protected_pages[protected_page_count++] = page_id;
                    }
                }
            }
        }
        if (protected_page_count != 0U) {
            protected_page_ids = protected_pages;
        }
        if (result == MYLITE_STORAGE_OK) {
            result = begin_write_journal_for_statement_pages(
                file,
                filename,
                &header,
                0,
                active_file_statement,
                protected_page_ids,
                protected_page_count
            );
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        if (!used_active_update_rewrite && !has_maintained_index_updates &&
            !has_maintained_index_retargets) {
            result = write_inline_update_pages(
                file,
                &header,
                table_id,
                row_id,
                row,
                row_size,
                index_entries,
                index_entry_count,
                index_entry_write_changed,
                &position,
                &next_page_id,
                &used_inline_update_pages
            );
        }
    }
    if (result == MYLITE_STORAGE_OK && !used_active_update_rewrite && !used_inline_update_pages) {
        result = write_row_payload_pages(file, &header, table_id, row, row_size, &position);
        if (result == MYLITE_STORAGE_OK && position.next_page_id == ULLONG_MAX) {
            result = MYLITE_STORAGE_FULL;
        }
        next_page_id = position.next_page_id;
        if (result == MYLITE_STORAGE_OK) {
            const mylite_storage_row_state_page row_state = {
                .table_id = table_id,
                .source_row_id = row_id,
                .replacement_row_id = position.row_page_id,
                .state_kind = MYLITE_STORAGE_FORMAT_ROW_STATE_KIND_REPLACE,
            };
            unsigned char state_page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
            encode_row_state_page(state_page, next_page_id, &row_state);
            const mylite_storage_pager pager = open_storage_pager(file, NULL, &header);
            result = pager_write_page(&pager, next_page_id, state_page);
        }
        if (result == MYLITE_STORAGE_OK && has_maintained_index_updates) {
            result = write_maintained_index_root_updates(
                file,
                &header,
                table_id,
                row_id,
                position.row_page_id,
                index_entries,
                &maintained_index_plan
            );
        }
        if (result == MYLITE_STORAGE_OK && has_maintained_index_updates) {
            result = write_branch_index_root_updates(
                file,
                &header,
                table_id,
                row_id,
                position.row_page_id,
                index_entries,
                &maintained_index_plan
            );
        }
        if (result == MYLITE_STORAGE_OK && has_maintained_index_retargets) {
            result = write_maintained_index_root_retargets(
                file,
                &header,
                table_id,
                row_id,
                position.row_page_id,
                &maintained_index_retarget_plan
            );
        }
        if (result == MYLITE_STORAGE_OK) {
            ++next_page_id;
            result = write_index_entry_pages(
                file,
                &header,
                (mylite_storage_index_entry_write){
                    .first_page_id = next_page_id,
                    .table_id = table_id,
                    .row_id = position.row_page_id,
                    .index_entries = index_entries,
                    .index_entry_count = index_entry_count,
                    .index_entry_changed = index_entry_write_changed,
                },
                &next_page_id
            );
        }
    }
    if (result == MYLITE_STORAGE_OK && !used_active_update_rewrite) {
        header.page_count = next_page_id;
        result = publish_header_for_statement(
            file,
            &header,
            active_file_statement,
            file_scope.active_read_statement
        );
        if (result == MYLITE_STORAGE_OK) {
            result = finish_write_journal_for_statement(file, filename, active_file_statement);
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        *out_new_row_id = position.row_page_id;
        if (preserve_index_entries) {
            if (position.row_page_id != row_id) {
                retarget_active_exact_index_cache_entries_in_statement(
                    active_cache_statement,
                    table_id,
                    row_id,
                    position.row_page_id
                );
            }
        } else {
            replace_active_exact_index_cache_entries_in_statement(
                active_cache_statement,
                table_id,
                row_id,
                position.row_page_id,
                index_entries,
                index_entry_count,
                index_entry_changed
            );
        }
        if (has_maintained_index_updates || has_maintained_index_retargets) {
            clear_exact_index_caches(active_cache_statement);
            clear_durable_exact_index_caches(filename);
        }
        const int active_row_id_unchanged = position.row_page_id == row_id;
        if (!active_row_id_unchanged) {
            record_row_state_in_statement_cache(
                active_cache_statement,
                &header,
                table_id,
                row_id,
                position.row_page_id,
                MYLITE_STORAGE_FORMAT_ROW_STATE_KIND_REPLACE
            );
            if (active_live_row_cache == NULL) {
                active_live_row_cache =
                    live_row_cache_for_statement(active_cache_statement, &header, table_id);
            }
            replace_active_live_row_in_cache(
                active_cache_statement,
                &header,
                table_id,
                &active_live_row_cache,
                row_id,
                position.row_page_id
            );
            replace_active_live_row_id_in_statement(
                active_cache_statement,
                filename,
                &header,
                table_id,
                row_id,
                position.row_page_id
            );
        }
        if (active_row_payload_cache != NULL) {
            replace_active_row_payload_in_cache(
                active_row_payload_cache,
                row_id,
                position.row_page_id,
                row,
                row_size,
                active_row_payload_entry,
                active_row_payload_bucket
            );
        }
        if (active_row_payload_entry == NULL) {
            (void)store_active_row_payload_in_statement(
                active_cache_statement,
                filename,
                &header,
                table_id,
                position.row_page_id,
                row,
                row_size
            );
        }
        if (!used_active_update_rewrite ||
            !statement_chain_has_deferred_durable_cache_retarget(active_file_statement, table_id)) {
            retarget_durable_caches_after_table_mutation_in_statement(
                active_file_statement,
                filename,
                &header,
                table_id
            );
        }
    }

    free(old_row_page.owned_payload);
    if (has_maintained_index_plan) {
        clear_maintained_index_update_plan(&maintained_index_plan);
    }
    if (catalog.bytes != NULL) {
        free_catalog_image(&catalog);
    }
    if (owns_update_file_scope) {
        if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
            result == MYLITE_STORAGE_OK) {
            result = MYLITE_STORAGE_IOERR;
        }
    } else {
        clear_existing_file_error_state(file);
    }
    if (result != MYLITE_STORAGE_OK) {
        *out_new_row_id = 0ULL;
    }
    return result;
}

static mylite_storage_result plan_maintained_index_root_retargets(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    const mylite_storage_maintained_index_update_plan *updated_roots,
    unsigned long long source_row_id,
    mylite_storage_maintained_index_retarget_plan *out_plan
) {
    *out_plan = (mylite_storage_maintained_index_retarget_plan){0};

    size_t offset = MYLITE_STORAGE_FORMAT_CATALOG_HEADER_SIZE;
    const unsigned long long record_count = catalog_record_count(catalog);
    for (unsigned long long i = 0ULL; i < record_count; ++i) {
        const unsigned char *record = catalog->bytes + offset;
        const size_t record_size = get_u32_le(record, MYLITE_STORAGE_FORMAT_RECORD_SIZE_OFFSET);
        if (record_is_index_root(record) && record_matches_table(record, schema_name, table_name) &&
            get_u64_le(record, MYLITE_STORAGE_FORMAT_RECORD_TABLE_ID_OFFSET) == table_id) {
            const unsigned long long root_page_id =
                get_u64_le(record, MYLITE_STORAGE_FORMAT_RECORD_DEFINITION_ROOT_PAGE_OFFSET);
            const unsigned index_number =
                get_u32_le(record, MYLITE_STORAGE_FORMAT_RECORD_FLAGS_OFFSET);
            if (maintained_index_update_plan_has_root_page(updated_roots, root_page_id)) {
                offset += record_size;
                continue;
            }
            if (!is_addressable_page_id(header, root_page_id)) {
                return MYLITE_STORAGE_CORRUPT;
            }

            unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
            mylite_storage_result result =
                read_page_at(file, root_page_id, header->page_size, page);
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            if (!is_maintained_index_root_page(page)) {
                if (is_index_branch_page(page)) {
                    return MYLITE_STORAGE_UNSUPPORTED;
                }
                offset += record_size;
                continue;
            }

            mylite_storage_maintained_index_root_page root_page = {0};
            result = decode_maintained_index_root_page(header, root_page_id, page, &root_page);
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            if (root_page.table_id != table_id || root_page.index_number != index_number) {
                return MYLITE_STORAGE_CORRUPT;
            }
            if (maintained_index_root_needs_tail_scan(&root_page)) {
                return MYLITE_STORAGE_UNSUPPORTED;
            }
            if (maintained_index_root_page_has_row_id(&root_page, source_row_id)) {
                result = append_maintained_index_retarget_plan_root(out_plan, root_page_id);
                if (result != MYLITE_STORAGE_OK) {
                    return result;
                }
            }
        }
        offset += record_size;
    }
    return MYLITE_STORAGE_OK;
}

static int maintained_index_update_plan_has_root_page(
    const mylite_storage_maintained_index_update_plan *plan,
    unsigned long long root_page_id
) {
    if (plan == NULL) {
        return 0;
    }
    for (size_t i = 0U; i < plan->count; ++i) {
        if (plan->entries[i].root_page_id == root_page_id) {
            return 1;
        }
    }
    for (size_t i = 0U; i < plan->branch_count; ++i) {
        if (plan->branch_entries[i].root_page_id == root_page_id) {
            return 1;
        }
    }
    return 0;
}

static mylite_storage_result append_maintained_index_retarget_plan_root(
    mylite_storage_maintained_index_retarget_plan *plan,
    unsigned long long root_page_id
) {
    if (plan->count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }
    mylite_storage_result result =
        append_maintained_index_retarget_plan_protected_page(plan, root_page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    plan->root_page_ids[plan->count++] = root_page_id;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_retarget_plan_protected_page(
    mylite_storage_maintained_index_retarget_plan *plan,
    unsigned long long page_id
) {
    if (maintained_index_retarget_plan_has_protected_page(plan, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (plan->protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }
    plan->protected_page_ids[plan->protected_page_count++] = page_id;
    return MYLITE_STORAGE_OK;
}

static int maintained_index_retarget_plan_has_protected_page(
    const mylite_storage_maintained_index_retarget_plan *plan,
    unsigned long long page_id
) {
    for (size_t i = 0U; i < plan->protected_page_count; ++i) {
        if (plan->protected_page_ids[i] == page_id) {
            return 1;
        }
    }
    return 0;
}

static int maintained_index_retarget_plan_is_empty(
    const mylite_storage_maintained_index_retarget_plan *plan
) {
    return plan->count == 0U;
}

static mylite_storage_result plan_maintained_index_root_updates(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    unsigned long long source_row_id,
    size_t replacement_row_size,
    const mylite_storage_index_entry *index_entries,
    size_t index_entry_count,
    const unsigned char *index_entry_changed,
    mylite_storage_maintained_index_update_plan *out_plan
) {
    init_maintained_index_update_plan(out_plan);
    if (index_entry_count == 0U) {
        return MYLITE_STORAGE_OK;
    }
    if (index_entry_count > SIZE_MAX / sizeof(*out_plan->index_entry_changed)) {
        return MYLITE_STORAGE_FULL;
    }

    if (index_entry_count <= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        out_plan->index_entry_changed = out_plan->inline_index_entry_changed;
    } else {
        out_plan->index_entry_changed =
            (unsigned char *)malloc(index_entry_count * sizeof(*out_plan->index_entry_changed));
        if (out_plan->index_entry_changed == NULL) {
            return MYLITE_STORAGE_NOMEM;
        }
    }
    for (size_t i = 0U; i < index_entry_count; ++i) {
        out_plan->index_entry_changed[i] = is_index_entry_changed(index_entry_changed, i) ? 1U : 0U;
    }

    for (size_t i = 0U; i < index_entry_count; ++i) {
        mylite_storage_catalog_entry root_entry = {0};
        mylite_storage_result result = find_index_root_record(
            catalog,
            schema_name,
            table_name,
            table_id,
            index_entries[i].index_number,
            &root_entry
        );
        if (result == MYLITE_STORAGE_NOTFOUND) {
            continue;
        }
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (out_plan->protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES ||
            maintained_index_update_plan_has_protected_page(
                out_plan,
                root_entry.definition_root_page
            )) {
            continue;
        }
        if (!is_addressable_page_id(header, root_entry.definition_root_page)) {
            return MYLITE_STORAGE_CORRUPT;
        }

        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        result = read_page_at(file, root_entry.definition_root_page, header->page_size, page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (!is_maintained_index_root_page(page)) {
            if (!is_index_branch_page(page)) {
                continue;
            }
            mylite_storage_index_branch_page branch_page = {0};
            result = decode_index_branch_page(
                header,
                root_entry.definition_root_page,
                page,
                &branch_page
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            result = plan_branch_index_root_update(
                file,
                header,
                &branch_page,
                table_id,
                index_entries[i].index_number,
                root_entry.definition_root_page,
                source_row_id,
                replacement_row_size,
                index_entries + i,
                i,
                out_plan
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            continue;
        }

        mylite_storage_maintained_index_root_page root_page = {0};
        result = decode_maintained_index_root_page(
            header,
            root_entry.definition_root_page,
            page,
            &root_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (root_page.table_id != table_id ||
            root_page.index_number != index_entries[i].index_number ||
            root_page.key_size != index_entries[i].key_size ||
            !maintained_index_root_page_has_row_id(&root_page, source_row_id)) {
            continue;
        }

        result =
            append_maintained_index_update_plan_entry(out_plan, i, root_entry.definition_root_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    if (maintained_index_update_plan_is_empty(out_plan)) {
        clear_maintained_index_update_plan(out_plan);
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_update_plan_entry(
    mylite_storage_maintained_index_update_plan *plan,
    size_t entry_index,
    unsigned long long root_page_id
) {
    if (plan->entries == NULL) {
        plan->entries = plan->inline_entries;
        plan->capacity = MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES;
    }
    if (plan->count == plan->capacity) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    mylite_storage_result result =
        append_maintained_index_update_plan_protected_page(plan, root_page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    plan->entries[plan->count++] = (mylite_storage_maintained_index_update){
        .entry_index = entry_index,
        .root_page_id = root_page_id,
    };
    plan->index_entry_changed[entry_index] = 0U;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_update_plan_branch(
    mylite_storage_maintained_index_update_plan *plan,
    size_t entry_index,
    unsigned long long root_page_id,
    unsigned long long leaf_page_id,
    size_t child_index,
    unsigned long long target_leaf_page_id,
    size_t target_child_index,
    unsigned index_number
) {
    if (plan->branch_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_OK;
    }

    size_t needed_pages = 0U;
    if (!maintained_index_update_plan_has_protected_page(plan, root_page_id)) {
        ++needed_pages;
    }
    if (leaf_page_id != root_page_id &&
        !maintained_index_update_plan_has_protected_page(plan, leaf_page_id)) {
        ++needed_pages;
    }
    if (target_leaf_page_id != root_page_id && target_leaf_page_id != leaf_page_id &&
        !maintained_index_update_plan_has_protected_page(plan, target_leaf_page_id)) {
        ++needed_pages;
    }
    if (needed_pages >
        MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - plan->protected_page_count) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_result result =
        append_maintained_index_update_plan_protected_page(plan, root_page_id);
    if (result == MYLITE_STORAGE_OK) {
        result = append_maintained_index_update_plan_protected_page(plan, leaf_page_id);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = append_maintained_index_update_plan_protected_page(plan, target_leaf_page_id);
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    plan->branch_entries[plan->branch_count++] = (mylite_storage_branch_index_update){
        .entry_index = entry_index,
        .root_page_id = root_page_id,
        .leaf_page_id = leaf_page_id,
        .target_leaf_page_id = target_leaf_page_id,
        .child_index = child_index,
        .target_child_index = target_child_index,
        .index_number = index_number,
        .move_to_child = leaf_page_id != target_leaf_page_id,
    };
    plan->index_entry_changed[entry_index] = 0U;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_update_plan_branch_refold(
    mylite_storage_maintained_index_update_plan *plan,
    size_t entry_index,
    unsigned long long root_page_id,
    unsigned long long leaf_page_id,
    size_t child_index,
    unsigned long long target_leaf_page_id,
    size_t target_child_index,
    unsigned index_number,
    const mylite_storage_index_branch_page *branch_page
) {
    if (plan->branch_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_OK;
    }

    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    size_t needed_pages = 0U;
    if (!maintained_index_update_plan_has_protected_page(plan, root_page_id)) {
        ++needed_pages;
    }
    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * branch_cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (!maintained_index_update_plan_has_protected_page(plan, child_page_id)) {
            ++needed_pages;
        }
    }
    if (needed_pages >
        MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - plan->protected_page_count) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_result result =
        append_maintained_index_update_plan_protected_page(plan, root_page_id);
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * branch_cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        result = append_maintained_index_update_plan_protected_page(plan, child_page_id);
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    plan->branch_entries[plan->branch_count++] = (mylite_storage_branch_index_update){
        .entry_index = entry_index,
        .root_page_id = root_page_id,
        .leaf_page_id = leaf_page_id,
        .target_leaf_page_id = target_leaf_page_id,
        .child_index = child_index,
        .target_child_index = target_child_index,
        .index_number = index_number,
        .move_to_child = 1,
        .refold_branch = 1,
    };
    plan->index_entry_changed[entry_index] = 0U;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_update_plan_protected_page(
    mylite_storage_maintained_index_update_plan *plan,
    unsigned long long page_id
) {
    if (maintained_index_update_plan_has_protected_page(plan, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (plan->protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    plan->protected_page_ids[plan->protected_page_count++] = page_id;
    return MYLITE_STORAGE_OK;
}

static int maintained_index_update_plan_has_protected_page(
    const mylite_storage_maintained_index_update_plan *plan,
    unsigned long long page_id
) {
    for (size_t i = 0U; i < plan->protected_page_count; ++i) {
        if (plan->protected_page_ids[i] == page_id) {
            return 1;
        }
    }
    return 0;
}

static int maintained_index_update_plan_is_empty(
    const mylite_storage_maintained_index_update_plan *plan
) {
    return plan->count == 0U && plan->branch_count == 0U;
}

static mylite_storage_result plan_branch_index_root_update(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    unsigned long long root_page_id,
    unsigned long long source_row_id,
    size_t replacement_row_size,
    const mylite_storage_index_entry *index_entry,
    size_t entry_index,
    mylite_storage_maintained_index_update_plan *out_plan
) {
    if (branch_page->table_id != table_id) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (branch_page->index_number != index_number || branch_page->level != 1U ||
        branch_page->entry_count == 0ULL || branch_page->child_count == 0U ||
        branch_page->key_size != index_entry->key_size ||
        branch_page->index_number != index_entry->index_number) {
        return MYLITE_STORAGE_OK;
    }
    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page->key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_OK;
    }
    const unsigned long long expected_child_count =
        ((branch_page->entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (expected_child_count != (unsigned long long)branch_page->child_count) {
        return MYLITE_STORAGE_OK;
    }

    unsigned long long replacement_row_id = 0ULL;
    mylite_storage_result result =
        predict_append_row_page_id(header, replacement_row_size, &replacement_row_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t child_index = 0U; child_index < branch_page->child_count; ++child_index) {
        const unsigned char *cell = branch_page->payload + (child_index * cell_size);
        const unsigned long long leaf_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        result = read_page_at(file, leaf_page_id, header->page_size, leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

        mylite_storage_index_leaf_page leaf_page = {0};
        result = decode_index_leaf_page(header, leaf_page_id, leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (leaf_page.table_id != table_id || leaf_page.index_number != index_number ||
            leaf_page.key_size != branch_page->key_size) {
            return MYLITE_STORAGE_CORRUPT;
        }

        int source_is_in_leaf = 0;
        for (size_t i = 0U; i < leaf_page.entry_count; ++i) {
            if (index_leaf_entry_row_id(&leaf_page, i) == source_row_id) {
                source_is_in_leaf = 1;
                break;
            }
        }
        if (!source_is_in_leaf) {
            continue;
        }
        if (index_branch_child_accepts_entry(
                branch_page,
                child_index,
                index_entry,
                replacement_row_id
            )) {
            return append_maintained_index_update_plan_branch(
                out_plan,
                entry_index,
                root_page_id,
                leaf_page_id,
                child_index,
                leaf_page_id,
                child_index,
                index_number
            );
        }

        unsigned long long target_leaf_page_id = 0ULL;
        result = find_index_branch_child_page(
            branch_page,
            index_entry->key,
            index_entry->key_size,
            replacement_row_id,
            &target_leaf_page_id
        );
        if (result == MYLITE_STORAGE_NOTFOUND) {
            const unsigned char *last_cell =
                branch_page->payload + ((branch_page->child_count - 1U) * cell_size);
            target_leaf_page_id =
                get_u64_le(last_cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
            result = MYLITE_STORAGE_OK;
        }
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

        size_t target_child_index = 0U;
        result =
            find_index_branch_child_offset(branch_page, target_leaf_page_id, &target_child_index);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (target_child_index == child_index || !index_branch_child_accepts_entry(
                                                     branch_page,
                                                     target_child_index,
                                                     index_entry,
                                                     replacement_row_id
                                                 )) {
            return MYLITE_STORAGE_OK;
        }

        unsigned char target_leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        result = read_page_at(file, target_leaf_page_id, header->page_size, target_leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        mylite_storage_index_leaf_page target_leaf_page = {0};
        result = decode_index_leaf_page(
            header,
            target_leaf_page_id,
            target_leaf_page_bytes,
            &target_leaf_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (target_leaf_page.table_id != table_id ||
            target_leaf_page.index_number != index_number ||
            target_leaf_page.key_size != branch_page->key_size) {
            return MYLITE_STORAGE_CORRUPT;
        }
        if (target_leaf_page.entry_count >= leaf_capacity) {
            return append_maintained_index_update_plan_branch_refold(
                out_plan,
                entry_index,
                root_page_id,
                leaf_page_id,
                child_index,
                target_leaf_page_id,
                target_child_index,
                index_number,
                branch_page
            );
        }
        if (leaf_page.entry_count <= 1U) {
            return append_maintained_index_update_plan_branch_refold(
                out_plan,
                entry_index,
                root_page_id,
                leaf_page_id,
                child_index,
                target_leaf_page_id,
                target_child_index,
                index_number,
                branch_page
            );
        }

        return append_maintained_index_update_plan_branch(
            out_plan,
            entry_index,
            root_page_id,
            leaf_page_id,
            child_index,
            target_leaf_page_id,
            target_child_index,
            index_number
        );
    }
    return MYLITE_STORAGE_OK;
}

static void init_maintained_index_update_plan(mylite_storage_maintained_index_update_plan *plan) {
    plan->index_entry_changed = NULL;
    plan->entries = NULL;
    plan->count = 0U;
    plan->capacity = 0U;
    plan->branch_count = 0U;
    plan->protected_page_count = 0U;
}

static mylite_storage_result write_maintained_index_root_updates(
    FILE *file,
    const mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id,
    const mylite_storage_index_entry *index_entries,
    const mylite_storage_maintained_index_update_plan *plan
) {
    const mylite_storage_pager pager = open_storage_pager(file, NULL, header);
    for (size_t i = 0U; i < plan->count; ++i) {
        const mylite_storage_maintained_index_update *update = plan->entries + i;
        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_result result = pager_read_page(&pager, update->root_page_id, page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = update_maintained_index_root_entry(
            page,
            header,
            update->root_page_id,
            table_id,
            source_row_id,
            replacement_row_id,
            index_entries + update->entry_index
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = pager_write_page(&pager, update->root_page_id, page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result write_branch_index_root_updates(
    FILE *file,
    const mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id,
    const mylite_storage_index_entry *index_entries,
    const mylite_storage_maintained_index_update_plan *plan
) {
    const mylite_storage_pager pager = open_storage_pager(file, NULL, header);
    for (size_t i = 0U; i < plan->branch_count; ++i) {
        const mylite_storage_branch_index_update *update = plan->branch_entries + i;
        mylite_storage_result result = update_branch_index_leaf_entry(
            &pager,
            header,
            table_id,
            source_row_id,
            replacement_row_id,
            index_entries + update->entry_index,
            update
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result write_maintained_index_root_retargets(
    FILE *file,
    const mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id,
    const mylite_storage_maintained_index_retarget_plan *plan
) {
    const mylite_storage_pager pager = open_storage_pager(file, NULL, header);
    for (size_t i = 0U; i < plan->count; ++i) {
        const unsigned long long root_page_id = plan->root_page_ids[i];
        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_result result = pager_read_page(&pager, root_page_id, page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = retarget_maintained_index_root_entry(
            page,
            header,
            root_page_id,
            table_id,
            source_row_id,
            replacement_row_id
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = pager_write_page(&pager, root_page_id, page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result update_branch_index_leaf_entry(
    const mylite_storage_pager *pager,
    const mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id,
    const mylite_storage_index_entry *index_entry,
    const mylite_storage_branch_index_update *update
) {
    unsigned char branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result = pager_read_page(pager, update->root_page_id, branch_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_branch_page branch_page = {0};
    result =
        decode_index_branch_page(header, update->root_page_id, branch_page_bytes, &branch_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    const size_t destination_child_index =
        update->move_to_child ? update->target_child_index : update->child_index;
    if (branch_page.table_id != table_id || branch_page.index_number != update->index_number ||
        branch_page.index_number != index_entry->index_number ||
        branch_page.key_size != index_entry->key_size || branch_page.level != 1U ||
        branch_page.entry_count == 0ULL || branch_page.child_count == 0U ||
        update->child_index >= branch_page.child_count ||
        destination_child_index >= branch_page.child_count ||
        !index_branch_child_accepts_entry(
            &branch_page,
            destination_child_index,
            index_entry,
            replacement_row_id
        )) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page.key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const unsigned long long expected_child_count =
        ((branch_page.entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (expected_child_count != (unsigned long long)branch_page.child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page.key_size;
    const unsigned char *branch_cell =
        branch_page.payload + (update->child_index * branch_cell_size);
    if (get_u64_le(branch_cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET) !=
        update->leaf_page_id) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (update->move_to_child) {
        const unsigned char *target_branch_cell =
            branch_page.payload + (update->target_child_index * branch_cell_size);
        if (get_u64_le(
                target_branch_cell,
                MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET
            ) != update->target_leaf_page_id ||
            update->target_leaf_page_id == update->leaf_page_id) {
            return MYLITE_STORAGE_CORRUPT;
        }
        if (update->refold_branch) {
            return refold_branch_index_update_entry(
                pager,
                header,
                table_id,
                source_row_id,
                replacement_row_id,
                index_entry,
                update,
                branch_page_bytes,
                &branch_page
            );
        }
        return move_branch_index_leaf_entry(
            pager,
            header,
            table_id,
            source_row_id,
            replacement_row_id,
            index_entry,
            update,
            branch_page_bytes,
            &branch_page
        );
    }

    unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = pager_read_page(pager, update->leaf_page_id, leaf_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    mylite_storage_index_leaf_page leaf_page = {0};
    result = decode_index_leaf_page(header, update->leaf_page_id, leaf_page_bytes, &leaf_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != update->index_number ||
        leaf_page.key_size != branch_page.key_size) {
        return MYLITE_STORAGE_CORRUPT;
    }

    mylite_storage_index_entryset entries = {
        .size = sizeof(entries),
    };
    result = append_index_leaf_entries_to_entryset(&leaf_page, &entries);
    const size_t before_remove_count = entries.entry_count;
    if (result == MYLITE_STORAGE_OK) {
        remove_index_entries_by_row_id(&entries, source_row_id);
        if (entries.entry_count + 1U != before_remove_count) {
            result = MYLITE_STORAGE_CORRUPT;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = append_raw_index_entry_to_entryset(&entries, replacement_row_id, index_entry);
    }

    unsigned char *updated_leaf_pages = NULL;
    size_t updated_leaf_page_count = 0U;
    if (result == MYLITE_STORAGE_OK) {
        result = prepare_index_leaf_pages(
            &updated_leaf_pages,
            &updated_leaf_page_count,
            update->leaf_page_id,
            table_id,
            index_entry->index_number,
            &entries
        );
    }
    if (result == MYLITE_STORAGE_OK && updated_leaf_page_count != 1U) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = refresh_index_branch_child_after_leaf_update(
            branch_page_bytes,
            header,
            update->root_page_id,
            &branch_page,
            update->leaf_page_id,
            updated_leaf_pages
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, update->leaf_page_id, updated_leaf_pages);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, update->root_page_id, branch_page_bytes);
    }

    free(updated_leaf_pages);
    mylite_storage_free_index_entryset(&entries);
    return result;
}

static mylite_storage_result move_branch_index_leaf_entry(
    const mylite_storage_pager *pager,
    const mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id,
    const mylite_storage_index_entry *index_entry,
    const mylite_storage_branch_index_update *update,
    unsigned char *branch_page_bytes,
    const mylite_storage_index_branch_page *branch_page
) {
    if (update->child_index >= branch_page->child_count ||
        update->target_child_index >= branch_page->child_count ||
        update->target_child_index == update->child_index) {
        return MYLITE_STORAGE_CORRUPT;
    }

    unsigned char source_leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result =
        pager_read_page(pager, update->leaf_page_id, source_leaf_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    mylite_storage_index_leaf_page source_leaf_page = {0};
    result = decode_index_leaf_page(
        header,
        update->leaf_page_id,
        source_leaf_page_bytes,
        &source_leaf_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char target_leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    if (result == MYLITE_STORAGE_OK) {
        result = pager_read_page(pager, update->target_leaf_page_id, target_leaf_page_bytes);
    }
    mylite_storage_index_leaf_page target_leaf_page = {0};
    if (result == MYLITE_STORAGE_OK) {
        result = decode_index_leaf_page(
            header,
            update->target_leaf_page_id,
            target_leaf_page_bytes,
            &target_leaf_page
        );
    }
    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page->key_size);
    if (result == MYLITE_STORAGE_OK &&
        (source_leaf_page.table_id != table_id ||
         source_leaf_page.index_number != update->index_number ||
         source_leaf_page.key_size != branch_page->key_size ||
         target_leaf_page.table_id != table_id ||
         target_leaf_page.index_number != update->index_number ||
         target_leaf_page.key_size != branch_page->key_size || leaf_capacity == 0U ||
         source_leaf_page.entry_count <= 1U || target_leaf_page.entry_count >= leaf_capacity)) {
        result = MYLITE_STORAGE_CORRUPT;
    }

    mylite_storage_index_entryset source_entries = {
        .size = sizeof(source_entries),
    };
    if (result == MYLITE_STORAGE_OK) {
        result = append_index_leaf_entries_to_entryset(&source_leaf_page, &source_entries);
    }
    const size_t before_remove_count = source_entries.entry_count;
    if (result == MYLITE_STORAGE_OK) {
        remove_index_entries_by_row_id(&source_entries, source_row_id);
        if (source_entries.entry_count + 1U != before_remove_count ||
            source_entries.entry_count == 0U) {
            result = MYLITE_STORAGE_CORRUPT;
        }
    }

    mylite_storage_index_entryset target_entries = {
        .size = sizeof(target_entries),
    };
    if (result == MYLITE_STORAGE_OK) {
        result = append_index_leaf_entries_to_entryset(&target_leaf_page, &target_entries);
    }
    if (result == MYLITE_STORAGE_OK) {
        result =
            append_raw_index_entry_to_entryset(&target_entries, replacement_row_id, index_entry);
    }

    unsigned char *updated_source_leaf_pages = NULL;
    size_t updated_source_leaf_page_count = 0U;
    if (result == MYLITE_STORAGE_OK) {
        result = prepare_index_leaf_pages(
            &updated_source_leaf_pages,
            &updated_source_leaf_page_count,
            update->leaf_page_id,
            table_id,
            index_entry->index_number,
            &source_entries
        );
    }
    if (result == MYLITE_STORAGE_OK && updated_source_leaf_page_count != 1U) {
        result = MYLITE_STORAGE_CORRUPT;
    }

    unsigned char *updated_target_leaf_pages = NULL;
    size_t updated_target_leaf_page_count = 0U;
    if (result == MYLITE_STORAGE_OK) {
        result = prepare_index_leaf_pages(
            &updated_target_leaf_pages,
            &updated_target_leaf_page_count,
            update->target_leaf_page_id,
            table_id,
            index_entry->index_number,
            &target_entries
        );
    }
    if (result == MYLITE_STORAGE_OK && updated_target_leaf_page_count != 1U) {
        result = MYLITE_STORAGE_CORRUPT;
    }

    if (result == MYLITE_STORAGE_OK) {
        result = refresh_index_branch_child_after_leaf_update(
            branch_page_bytes,
            header,
            update->root_page_id,
            branch_page,
            update->leaf_page_id,
            updated_source_leaf_pages
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = refresh_index_branch_child_after_leaf_update(
            branch_page_bytes,
            header,
            update->root_page_id,
            branch_page,
            update->target_leaf_page_id,
            updated_target_leaf_pages
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, update->leaf_page_id, updated_source_leaf_pages);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, update->target_leaf_page_id, updated_target_leaf_pages);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, update->root_page_id, branch_page_bytes);
    }

    free(updated_target_leaf_pages);
    free(updated_source_leaf_pages);
    mylite_storage_free_index_entryset(&target_entries);
    mylite_storage_free_index_entryset(&source_entries);
    return result;
}

static mylite_storage_result refold_branch_index_update_entry(
    const mylite_storage_pager *pager,
    const mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id,
    const mylite_storage_index_entry *index_entry,
    const mylite_storage_branch_index_update *update,
    unsigned char *branch_page_bytes,
    const mylite_storage_index_branch_page *branch_page
) {
    if (update->child_index >= branch_page->child_count ||
        update->target_child_index >= branch_page->child_count ||
        update->target_child_index == update->child_index ||
        branch_page->child_count > MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page->key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const unsigned long long expected_child_count =
        ((branch_page->entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (expected_child_count != (unsigned long long)branch_page->child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    unsigned long long child_page_ids[MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN] = {0};
    mylite_storage_index_entryset entries = {
        .size = sizeof(entries),
    };
    int source_child_contains_row = 0;
    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * branch_cell_size);
        child_page_ids[i] =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if ((i == update->child_index && child_page_ids[i] != update->leaf_page_id) ||
            (i == update->target_child_index && child_page_ids[i] != update->target_leaf_page_id)) {
            mylite_storage_free_index_entryset(&entries);
            return MYLITE_STORAGE_CORRUPT;
        }

        unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_result result = pager_read_page(pager, child_page_ids[i], leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            mylite_storage_free_index_entryset(&entries);
            return result;
        }

        mylite_storage_index_leaf_page leaf_page = {0};
        result = decode_index_leaf_page(header, child_page_ids[i], leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            mylite_storage_free_index_entryset(&entries);
            return result;
        }
        if (leaf_page.table_id != table_id || leaf_page.index_number != update->index_number ||
            leaf_page.key_size != branch_page->key_size || leaf_page.entry_count == 0U) {
            mylite_storage_free_index_entryset(&entries);
            return MYLITE_STORAGE_CORRUPT;
        }
        if (i == update->child_index) {
            for (size_t leaf_entry = 0U; leaf_entry < leaf_page.entry_count; ++leaf_entry) {
                if (index_leaf_entry_row_id(&leaf_page, leaf_entry) == source_row_id) {
                    source_child_contains_row = 1;
                    break;
                }
            }
        }
        result = append_index_leaf_entries_to_entryset(&leaf_page, &entries);
        if (result != MYLITE_STORAGE_OK) {
            mylite_storage_free_index_entryset(&entries);
            return result;
        }
    }
    if (!source_child_contains_row ||
        (unsigned long long)entries.entry_count != branch_page->entry_count) {
        mylite_storage_free_index_entryset(&entries);
        return MYLITE_STORAGE_CORRUPT;
    }

    mylite_storage_result result = MYLITE_STORAGE_OK;
    const size_t before_remove_count = entries.entry_count;
    remove_index_entries_by_row_id(&entries, source_row_id);
    if (entries.entry_count + 1U != before_remove_count) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = append_raw_index_entry_to_entryset(&entries, replacement_row_id, index_entry);
    }
    if (result == MYLITE_STORAGE_OK &&
        (unsigned long long)entries.entry_count != branch_page->entry_count) {
        result = MYLITE_STORAGE_CORRUPT;
    }

    size_t key_size = 0U;
    size_t *order = NULL;
    if (result == MYLITE_STORAGE_OK) {
        result = index_entryset_fixed_key_size(&entries, &key_size);
    }
    if (result == MYLITE_STORAGE_OK && key_size != branch_page->key_size) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = build_raw_index_entry_order(&entries, &order);
    }

    unsigned char *updated_leaf_pages = NULL;
    unsigned long long child_max_row_ids[MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN] = {0};
    unsigned char *child_max_keys = NULL;
    if (result == MYLITE_STORAGE_OK) {
        if (branch_page->child_count > SIZE_MAX / MYLITE_STORAGE_FORMAT_PAGE_SIZE ||
            branch_page->key_size == 0U ||
            branch_page->child_count > SIZE_MAX / branch_page->key_size) {
            result = MYLITE_STORAGE_FULL;
        } else {
            updated_leaf_pages =
                (unsigned char *)malloc(branch_page->child_count * MYLITE_STORAGE_FORMAT_PAGE_SIZE);
            child_max_keys =
                (unsigned char *)malloc(branch_page->child_count * branch_page->key_size);
            if (updated_leaf_pages == NULL || child_max_keys == NULL) {
                result = MYLITE_STORAGE_NOMEM;
            }
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        const size_t leaf_cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE + branch_page->key_size;
        size_t first_entry = 0U;
        for (size_t i = 0U; i < branch_page->child_count; ++i) {
            const size_t remaining_entries = entries.entry_count - first_entry;
            const size_t remaining_children = branch_page->child_count - i;
            if (remaining_entries < remaining_children) {
                result = MYLITE_STORAGE_CORRUPT;
                break;
            }
            size_t leaf_entry_count =
                remaining_entries > leaf_capacity ? leaf_capacity : remaining_entries;
            const size_t minimum_remaining_entries = remaining_children - 1U;
            if (leaf_entry_count > remaining_entries - minimum_remaining_entries) {
                leaf_entry_count = remaining_entries - minimum_remaining_entries;
            }
            if (leaf_entry_count == 0U || leaf_entry_count > leaf_capacity) {
                result = MYLITE_STORAGE_CORRUPT;
                break;
            }

            unsigned char *leaf_page = updated_leaf_pages + (i * MYLITE_STORAGE_FORMAT_PAGE_SIZE);
            encode_index_leaf_page(
                leaf_page,
                child_page_ids[i],
                table_id,
                update->index_number,
                &entries,
                order,
                first_entry,
                leaf_entry_count,
                branch_page->key_size,
                MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET +
                    (leaf_entry_count * leaf_cell_size)
            );
            read_encoded_index_leaf_max_cell(
                leaf_page,
                branch_page->key_size,
                child_max_row_ids + i,
                child_max_keys + (i * branch_page->key_size)
            );
            first_entry += leaf_entry_count;
        }
        if (result == MYLITE_STORAGE_OK && first_entry != entries.entry_count) {
            result = MYLITE_STORAGE_CORRUPT;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = encode_index_branch_page(
            branch_page_bytes,
            update->root_page_id,
            table_id,
            update->index_number,
            1U,
            branch_page->key_size,
            branch_page->entry_count,
            child_page_ids,
            child_max_row_ids,
            child_max_keys,
            branch_page->child_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        mylite_storage_index_branch_page updated_branch_page = {0};
        result = decode_index_branch_page(
            header,
            update->root_page_id,
            branch_page_bytes,
            &updated_branch_page
        );
    }
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < branch_page->child_count; ++i) {
        result = pager_write_page(
            pager,
            child_page_ids[i],
            updated_leaf_pages + (i * MYLITE_STORAGE_FORMAT_PAGE_SIZE)
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, update->root_page_id, branch_page_bytes);
    }

    free(child_max_keys);
    free(updated_leaf_pages);
    free(order);
    mylite_storage_free_index_entryset(&entries);
    return result;
}

static int index_branch_child_accepts_entry(
    const mylite_storage_index_branch_page *branch_page,
    size_t child_index,
    const mylite_storage_index_entry *index_entry,
    unsigned long long row_id
) {
    if (child_index >= branch_page->child_count) {
        return 0;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    if (child_index != 0U) {
        const unsigned char *previous_cell =
            branch_page->payload + ((child_index - 1U) * cell_size);
        if (compare_index_entry_to_branch_cell(
                index_entry,
                row_id,
                previous_cell,
                branch_page->key_size
            ) <= 0) {
            return 0;
        }
    }
    if (child_index + 1U == branch_page->child_count) {
        return 1;
    }

    const unsigned char *current_cell = branch_page->payload + (child_index * cell_size);
    return compare_index_entry_to_branch_cell(
               index_entry,
               row_id,
               current_cell,
               branch_page->key_size
           ) <= 0;
}

static int compare_index_entry_to_branch_cell(
    const mylite_storage_index_entry *index_entry,
    unsigned long long row_id,
    const unsigned char *cell,
    size_t key_size
) {
    const int key_cmp = memcmp(
        index_entry->key,
        cell + MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_KEY_OFFSET,
        key_size
    );
    if (key_cmp != 0) {
        return key_cmp;
    }

    const unsigned long long max_row_id =
        get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_ROW_ID_OFFSET);
    if (row_id > max_row_id) {
        return 1;
    }
    return row_id == max_row_id ? 0 : -1;
}

static mylite_storage_result refresh_index_branch_child_after_leaf_update(
    unsigned char *branch_page_bytes,
    const mylite_storage_header *header,
    unsigned long long branch_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long leaf_page_id,
    const unsigned char *leaf_page
) {
    const size_t leaf_entry_count =
        get_u32_le(leaf_page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_COUNT_OFFSET);
    if (leaf_entry_count == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE + branch_page->key_size;
    const unsigned char *leaf_cell = leaf_page + MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET +
                                     ((leaf_entry_count - 1U) * leaf_cell_size);
    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    unsigned char *branch_cell = NULL;
    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        unsigned char *candidate = branch_page_bytes +
                                   MYLITE_STORAGE_FORMAT_INDEX_BRANCH_PAYLOAD_OFFSET +
                                   (i * branch_cell_size);
        const unsigned long long child_page_id =
            get_u64_le(candidate, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (child_page_id == leaf_page_id) {
            branch_cell = candidate;
            break;
        }
    }
    if (branch_cell == NULL) {
        return MYLITE_STORAGE_CORRUPT;
    }

    put_u64_le(
        branch_cell,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_ROW_ID_OFFSET,
        get_u64_le(leaf_cell, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET)
    );
    memcpy(
        branch_cell + MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_KEY_OFFSET,
        leaf_cell + MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET,
        branch_page->key_size
    );
    put_u64_le(branch_page_bytes, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET, 0ULL);
    put_u64_le(
        branch_page_bytes,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET,
        checksum_page_zero_tail(
            branch_page_bytes,
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET,
            branch_page->used_bytes
        )
    );

    mylite_storage_index_branch_page updated_branch_page = {0};
    return decode_index_branch_page(
        header,
        branch_page_id,
        branch_page_bytes,
        &updated_branch_page
    );
}

static mylite_storage_result update_maintained_index_root_entry(
    unsigned char *page,
    const mylite_storage_header *header,
    unsigned long long page_id,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id,
    const mylite_storage_index_entry *index_entry
) {
    mylite_storage_result result =
        delete_maintained_index_root_entry(page, header, page_id, source_row_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    return insert_maintained_index_root_entry(
        page,
        header,
        page_id,
        table_id,
        replacement_row_id,
        index_entry
    );
}

static mylite_storage_result retarget_maintained_index_root_entry(
    unsigned char *page,
    const mylite_storage_header *header,
    unsigned long long page_id,
    unsigned long long table_id,
    unsigned long long source_row_id,
    unsigned long long replacement_row_id
) {
    mylite_storage_maintained_index_root_page root_page = {0};
    mylite_storage_result result =
        decode_maintained_index_root_page(header, page_id, page, &root_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (root_page.table_id != table_id || root_page.entry_count == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    mylite_storage_index_entryset entries = {
        .size = sizeof(entries),
    };
    int retargeted = 0;
    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_HEADER_SIZE + root_page.key_size;
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < root_page.entry_count; ++i) {
        const unsigned char *cell = root_page.payload + (i * cell_size);
        const unsigned long long row_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_ROW_ID_OFFSET);
        const mylite_storage_index_entry index_entry = {
            .size = sizeof(index_entry),
            .index_number = root_page.index_number,
            .key_size = root_page.key_size,
            .key = cell + MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_KEY_OFFSET,
        };
        const unsigned long long stored_row_id =
            row_id == source_row_id ? replacement_row_id : row_id;
        retargeted = retargeted || row_id == source_row_id;
        result = append_raw_index_entry_to_entryset(&entries, stored_row_id, &index_entry);
    }
    if (result == MYLITE_STORAGE_OK && !retargeted) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = encode_maintained_index_root_page_from_entryset(
            page,
            page_id,
            table_id,
            root_page.index_number,
            root_page.key_size,
            &entries
        );
    }

    mylite_storage_free_index_entryset(&entries);
    return result;
}

static void clear_maintained_index_update_plan(mylite_storage_maintained_index_update_plan *plan) {
    if (plan->index_entry_changed != NULL &&
        plan->index_entry_changed != plan->inline_index_entry_changed) {
        free(plan->index_entry_changed);
    }
    if (plan->entries != NULL && plan->entries != plan->inline_entries) {
        free(plan->entries);
    }
    init_maintained_index_update_plan(plan);
}

mylite_storage_result mylite_storage_delete_row(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    unsigned long long row_id
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0' || row_id == 0ULL) {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_update_file_scope file_scope = {0};
    mylite_storage_result result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;
    mylite_storage_statement *active_file_statement = file_scope.active_statement;
    mylite_storage_statement *active_cache_statement =
        active_cache_statement_from_statement(active_file_statement);

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    mylite_storage_maintained_index_delete_plan maintained_index_plan = {0};
    unsigned long long table_id = 0ULL;
    mylite_storage_row_page row_page = {0};
    unsigned char row_buffer[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_record(&catalog, schema_name, table_name, &table_entry);
    }
    if (result == MYLITE_STORAGE_OK) {
        table_id = table_entry.table_id;
    }
    if (result == MYLITE_STORAGE_OK) {
        seed_active_live_row_id_cache(filename, &header, table_id);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = validate_direct_live_row(file, &header, table_id, row_id, row_buffer, &row_page);
    }
    if (result == MYLITE_STORAGE_OK && header.page_count == ULLONG_MAX) {
        result = MYLITE_STORAGE_FULL;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = plan_maintained_index_root_deletes(
            file,
            &header,
            &catalog,
            table_id,
            schema_name,
            table_name,
            row_id,
            &maintained_index_plan
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal_for_statement_pages(
            file,
            filename,
            &header,
            0,
            active_file_statement,
            maintained_index_plan.protected_page_ids,
            maintained_index_plan.protected_page_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = write_maintained_index_root_deletes(file, &header, row_id, &maintained_index_plan);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = write_branch_index_root_deletes(
            file,
            &header,
            table_id,
            row_id,
            &maintained_index_plan
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        const unsigned long long state_page_id = header.page_count;
        const mylite_storage_row_state_page row_state = {
            .table_id = table_id,
            .source_row_id = row_id,
            .replacement_row_id = 0ULL,
            .state_kind = MYLITE_STORAGE_FORMAT_ROW_STATE_KIND_DELETE,
        };
        unsigned char state_page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        encode_row_state_page(state_page, state_page_id, &row_state);
        const mylite_storage_pager pager = open_storage_pager(file, NULL, &header);
        result = pager_write_page(&pager, state_page_id, state_page);
        if (result == MYLITE_STORAGE_OK) {
            ++header.page_count;
            result = publish_header(file, &header);
            if (result == MYLITE_STORAGE_OK) {
                result = finish_write_journal(file, filename);
            }
        }
    }

    free(row_page.owned_payload);
    free_catalog_image(&catalog);
    if (result == MYLITE_STORAGE_OK) {
        record_row_state_in_statement_cache(
            active_cache_statement,
            &header,
            table_id,
            row_id,
            0ULL,
            MYLITE_STORAGE_FORMAT_ROW_STATE_KIND_DELETE
        );
        replace_active_exact_index_cache_entries(filename, table_id, row_id, 0ULL, NULL, 0U, NULL);
        replace_active_live_row(file, &header, table_id, row_id, 0ULL);
        remove_active_live_row_id(filename, &header, table_id, row_id);
        remove_active_row_payload(filename, &header, table_id, row_id);
        retarget_durable_caches_after_table_mutation_in_statement(
            active_file_statement,
            filename,
            &header,
            table_id
        );
    }
    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

static mylite_storage_result plan_maintained_index_root_deletes(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    unsigned long long row_id,
    mylite_storage_maintained_index_delete_plan *out_plan
) {
    *out_plan = (mylite_storage_maintained_index_delete_plan){0};

    size_t offset = MYLITE_STORAGE_FORMAT_CATALOG_HEADER_SIZE;
    const unsigned long long record_count = catalog_record_count(catalog);
    for (unsigned long long i = 0ULL; i < record_count; ++i) {
        const unsigned char *record = catalog->bytes + offset;
        const size_t record_size = get_u32_le(record, MYLITE_STORAGE_FORMAT_RECORD_SIZE_OFFSET);
        if (record_is_index_root(record) && record_matches_table(record, schema_name, table_name) &&
            get_u64_le(record, MYLITE_STORAGE_FORMAT_RECORD_TABLE_ID_OFFSET) == table_id) {
            const unsigned long long root_page_id =
                get_u64_le(record, MYLITE_STORAGE_FORMAT_RECORD_DEFINITION_ROOT_PAGE_OFFSET);
            const unsigned index_number =
                get_u32_le(record, MYLITE_STORAGE_FORMAT_RECORD_FLAGS_OFFSET);
            if (!is_addressable_page_id(header, root_page_id)) {
                return MYLITE_STORAGE_CORRUPT;
            }

            unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
            mylite_storage_result result =
                read_page_at(file, root_page_id, header->page_size, page);
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            if (is_maintained_index_root_page(page)) {
                mylite_storage_maintained_index_root_page root_page = {0};
                result = decode_maintained_index_root_page(header, root_page_id, page, &root_page);
                if (result != MYLITE_STORAGE_OK) {
                    return result;
                }
                if (root_page.table_id != table_id) {
                    return MYLITE_STORAGE_CORRUPT;
                }
                if (root_page.index_number != index_number) {
                    return MYLITE_STORAGE_CORRUPT;
                }
                if (maintained_index_root_page_has_row_id(&root_page, row_id)) {
                    result = append_maintained_index_delete_plan_root(out_plan, root_page_id);
                    if (result == MYLITE_STORAGE_UNSUPPORTED) {
                        *out_plan = (mylite_storage_maintained_index_delete_plan){0};
                        return MYLITE_STORAGE_OK;
                    }
                    if (result != MYLITE_STORAGE_OK) {
                        return result;
                    }
                }
            } else if (is_index_branch_page(page)) {
                mylite_storage_index_branch_page branch_page = {0};
                result = decode_index_branch_page(header, root_page_id, page, &branch_page);
                if (result != MYLITE_STORAGE_OK) {
                    return result;
                }
                result = plan_branch_index_root_delete(
                    file,
                    header,
                    &branch_page,
                    table_id,
                    index_number,
                    root_page_id,
                    row_id,
                    out_plan
                );
                if (result != MYLITE_STORAGE_OK) {
                    return result;
                }
            }
        }
        offset += record_size;
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_delete_plan_root(
    mylite_storage_maintained_index_delete_plan *plan,
    unsigned long long root_page_id
) {
    if (plan->count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }
    mylite_storage_result result =
        append_maintained_index_delete_plan_protected_page(plan, root_page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    plan->root_page_ids[plan->count++] = root_page_id;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_delete_plan_branch(
    mylite_storage_maintained_index_delete_plan *plan,
    unsigned long long root_page_id,
    unsigned long long leaf_page_id,
    size_t child_index,
    unsigned index_number,
    int remove_child,
    int collapse_child_removal,
    int refold_child_removal
) {
    if (plan->branch_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    size_t needed_pages = 0U;
    if (!maintained_index_delete_plan_has_protected_page(plan, root_page_id)) {
        ++needed_pages;
    }
    if (!maintained_index_delete_plan_has_protected_page(plan, leaf_page_id)) {
        ++needed_pages;
    }
    if (needed_pages >
        MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES - plan->protected_page_count) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    mylite_storage_result result =
        append_maintained_index_delete_plan_protected_page(plan, root_page_id);
    if (result == MYLITE_STORAGE_OK) {
        result = append_maintained_index_delete_plan_protected_page(plan, leaf_page_id);
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    plan->branch_entries[plan->branch_count++] = (mylite_storage_branch_index_delete){
        .root_page_id = root_page_id,
        .leaf_page_id = leaf_page_id,
        .child_index = child_index,
        .index_number = index_number,
        .remove_child = remove_child,
        .collapse_child_removal = collapse_child_removal,
        .refold_child_removal = refold_child_removal,
    };
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_delete_plan_protected_page(
    mylite_storage_maintained_index_delete_plan *plan,
    unsigned long long page_id
) {
    if (maintained_index_delete_plan_has_protected_page(plan, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (plan->protected_page_count >= MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    plan->protected_page_ids[plan->protected_page_count++] = page_id;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_maintained_index_delete_plan_free_list_reclaim_pages(
    mylite_storage_maintained_index_delete_plan *plan,
    FILE *file,
    const mylite_storage_header *header,
    unsigned long long first_page_id,
    unsigned long long page_count
) {
    mylite_storage_free_list_reclaim_plan reclaim_plan = {0};
    mylite_storage_result result =
        plan_reclaimed_free_list_run(file, header, first_page_id, page_count, &reclaim_plan);
    unsigned long long protected_page_ids[MYLITE_STORAGE_FREE_LIST_RECLAIM_MAX_WRITES] = {0};
    size_t protected_page_count = 0U;
    if (result == MYLITE_STORAGE_OK) {
        result = append_free_list_reclaim_existing_write_page_ids(
            &reclaim_plan,
            first_page_id,
            protected_page_ids,
            &protected_page_count
        );
    }
    for (size_t protected_index = 0U;
         result == MYLITE_STORAGE_OK && protected_index < protected_page_count;
         ++protected_index) {
        result = append_maintained_index_delete_plan_protected_page(
            plan,
            protected_page_ids[protected_index]
        );
    }
    return result;
}

static int maintained_index_delete_plan_has_protected_page(
    const mylite_storage_maintained_index_delete_plan *plan,
    unsigned long long page_id
) {
    for (size_t i = 0U; i < plan->protected_page_count; ++i) {
        if (plan->protected_page_ids[i] == page_id) {
            return 1;
        }
    }
    return 0;
}

static mylite_storage_result plan_branch_index_root_delete(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    unsigned long long root_page_id,
    unsigned long long row_id,
    mylite_storage_maintained_index_delete_plan *out_plan
) {
    if (branch_page->table_id != table_id) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (branch_page->index_number != index_number || branch_page->level != 1U ||
        branch_page->entry_count == 0ULL || branch_page->child_count == 0U) {
        return MYLITE_STORAGE_OK;
    }

    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page->key_size);
    if (leaf_capacity == 0U || branch_page->entry_count <= 1ULL) {
        return MYLITE_STORAGE_OK;
    }
    const unsigned long long current_expected_child_count =
        ((branch_page->entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (current_expected_child_count != (unsigned long long)branch_page->child_count) {
        return MYLITE_STORAGE_OK;
    }
    const unsigned long long new_entry_count = branch_page->entry_count - 1ULL;
    const unsigned long long expected_child_count =
        ((new_entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    const int removes_child =
        branch_page->child_count > 1U &&
        expected_child_count + 1ULL == (unsigned long long)branch_page->child_count;
    if (expected_child_count != (unsigned long long)branch_page->child_count && !removes_child) {
        return MYLITE_STORAGE_OK;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t child_index = 0U; child_index < branch_page->child_count; ++child_index) {
        const unsigned char *cell = branch_page->payload + (child_index * cell_size);
        const unsigned long long leaf_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_result result =
            read_page_at(file, leaf_page_id, header->page_size, leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

        mylite_storage_index_leaf_page leaf_page = {0};
        result = decode_index_leaf_page(header, leaf_page_id, leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (leaf_page.table_id != table_id || leaf_page.index_number != index_number ||
            leaf_page.key_size != branch_page->key_size) {
            return MYLITE_STORAGE_CORRUPT;
        }
        int leaf_contains_row = 0;
        for (size_t i = 0U; i < leaf_page.entry_count; ++i) {
            if (index_leaf_entry_row_id(&leaf_page, i) == row_id) {
                leaf_contains_row = 1;
                break;
            }
        }
        if (!leaf_contains_row) {
            continue;
        }

        if (removes_child && leaf_page.entry_count > 1U) {
            const int fits_maintained_root =
                new_entry_count <= maintained_index_root_entry_capacity(branch_page->key_size);
            int has_live_overlay = 0;
            if (fits_maintained_root) {
                result = index_branch_tail_has_live_overlay(
                    file,
                    header,
                    table_id,
                    index_number,
                    branch_page,
                    &has_live_overlay
                );
                if (result != MYLITE_STORAGE_OK) {
                    return result;
                }
                if (has_live_overlay) {
                    continue;
                }
            }
            const int collapse_child_removal = fits_maintained_root;
            result = append_maintained_index_delete_plan_protected_page(out_plan, root_page_id);
            if (result == MYLITE_STORAGE_OK && !collapse_child_removal) {
                for (size_t protect_child = 0U; protect_child < branch_page->child_count;
                     ++protect_child) {
                    const unsigned char *protect_cell =
                        branch_page->payload + (protect_child * cell_size);
                    const unsigned long long protect_leaf_page_id = get_u64_le(
                        protect_cell,
                        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET
                    );
                    result = append_maintained_index_delete_plan_protected_page(
                        out_plan,
                        protect_leaf_page_id
                    );
                    if (result != MYLITE_STORAGE_OK) {
                        break;
                    }
                }
            }
            if (result == MYLITE_STORAGE_OK) {
                const unsigned char *reclaimed_cell =
                    branch_page->payload + ((branch_page->child_count - 1U) * cell_size);
                const unsigned long long reclaimed_leaf_page_id = get_u64_le(
                    reclaimed_cell,
                    MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET
                );
                result = append_maintained_index_delete_plan_protected_page(
                    out_plan,
                    reclaimed_leaf_page_id
                );
                if (result == MYLITE_STORAGE_OK) {
                    result = append_maintained_index_delete_plan_free_list_reclaim_pages(
                        out_plan,
                        file,
                        header,
                        reclaimed_leaf_page_id,
                        1ULL
                    );
                }
            }
            if (result == MYLITE_STORAGE_UNSUPPORTED) {
                *out_plan = (mylite_storage_maintained_index_delete_plan){0};
                return MYLITE_STORAGE_OK;
            }
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }

            result = append_maintained_index_delete_plan_branch(
                out_plan,
                root_page_id,
                leaf_page_id,
                child_index,
                index_number,
                0,
                collapse_child_removal,
                !collapse_child_removal
            );
            if (result == MYLITE_STORAGE_UNSUPPORTED) {
                *out_plan = (mylite_storage_maintained_index_delete_plan){0};
                return MYLITE_STORAGE_OK;
            }
            return result;
        }

        if ((!removes_child && leaf_page.entry_count <= 1U) ||
            (removes_child && leaf_page.entry_count != 1U)) {
            continue;
        }
        if (removes_child) {
            result = append_maintained_index_delete_plan_free_list_reclaim_pages(
                out_plan,
                file,
                header,
                leaf_page_id,
                1ULL
            );
            if (result == MYLITE_STORAGE_UNSUPPORTED) {
                *out_plan = (mylite_storage_maintained_index_delete_plan){0};
                return MYLITE_STORAGE_OK;
            }
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
        }
        result = append_maintained_index_delete_plan_branch(
            out_plan,
            root_page_id,
            leaf_page_id,
            child_index,
            index_number,
            removes_child,
            0,
            0
        );
        if (result == MYLITE_STORAGE_UNSUPPORTED) {
            *out_plan = (mylite_storage_maintained_index_delete_plan){0};
            return MYLITE_STORAGE_OK;
        }
        return result;
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result write_maintained_index_root_deletes(
    FILE *file,
    const mylite_storage_header *header,
    unsigned long long row_id,
    const mylite_storage_maintained_index_delete_plan *plan
) {
    const mylite_storage_pager pager = open_storage_pager(file, NULL, header);
    for (size_t i = 0U; i < plan->count; ++i) {
        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_result result = pager_read_page(&pager, plan->root_page_ids[i], page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = delete_maintained_index_root_entry(page, header, plan->root_page_ids[i], row_id);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = refill_maintained_index_root_from_overflow_tail(
            file,
            header,
            plan->root_page_ids[i],
            page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = pager_write_page(&pager, plan->root_page_ids[i], page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result delete_maintained_index_root_entry(
    unsigned char *page,
    const mylite_storage_header *header,
    unsigned long long page_id,
    unsigned long long row_id
) {
    mylite_storage_maintained_index_root_page root_page = {0};
    mylite_storage_result result =
        decode_maintained_index_root_page(header, page_id, page, &root_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_HEADER_SIZE + root_page.key_size;
    unsigned char *payload = page + MYLITE_STORAGE_FORMAT_INDEX_ROOT_PAYLOAD_OFFSET;
    size_t write_index = 0U;
    for (size_t read_index = 0U; read_index < root_page.entry_count; ++read_index) {
        unsigned char *source = payload + (read_index * cell_size);
        if (get_u64_le(source, MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_ROW_ID_OFFSET) == row_id) {
            continue;
        }
        if (write_index != read_index) {
            memmove(payload + (write_index * cell_size), source, cell_size);
        }
        ++write_index;
    }
    if (write_index == root_page.entry_count) {
        return MYLITE_STORAGE_OK;
    }

    const size_t old_used_bytes = root_page.used_bytes;
    const size_t used_bytes =
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_PAYLOAD_OFFSET + (write_index * cell_size);
    memset(page + used_bytes, 0, old_used_bytes - used_bytes);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_COUNT_OFFSET, (unsigned)write_index);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_ROOT_USED_BYTES_OFFSET, (unsigned)used_bytes);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_ROOT_FLAGS_OFFSET, root_page.flags);
    put_u64_le(page, MYLITE_STORAGE_FORMAT_INDEX_ROOT_CHECKSUM_OFFSET, 0ULL);
    put_u64_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_CHECKSUM_OFFSET,
        checksum_page_zero_tail(page, MYLITE_STORAGE_FORMAT_INDEX_ROOT_CHECKSUM_OFFSET, used_bytes)
    );
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result write_branch_index_root_deletes(
    FILE *file,
    mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long row_id,
    const mylite_storage_maintained_index_delete_plan *plan
) {
    const mylite_storage_pager pager = open_storage_pager(file, NULL, header);
    for (size_t i = 0U; i < plan->branch_count; ++i) {
        mylite_storage_result result = delete_branch_index_leaf_entry(
            &pager,
            header,
            table_id,
            row_id,
            plan->branch_entries + i
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result delete_branch_index_leaf_entry(
    const mylite_storage_pager *pager,
    mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long row_id,
    const mylite_storage_branch_index_delete *delete_entry
) {
    if (delete_entry->remove_child) {
        return remove_branch_index_child_entry(pager, header, table_id, row_id, delete_entry);
    }
    if (delete_entry->collapse_child_removal) {
        return collapse_branch_index_child_count_delete_entry(
            pager,
            header,
            table_id,
            row_id,
            delete_entry
        );
    }
    if (delete_entry->refold_child_removal) {
        return refold_branch_index_child_count_delete_entry(
            pager,
            header,
            table_id,
            row_id,
            delete_entry
        );
    }

    unsigned char branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result =
        pager_read_page(pager, delete_entry->root_page_id, branch_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_branch_page branch_page = {0};
    result = decode_index_branch_page(
        header,
        delete_entry->root_page_id,
        branch_page_bytes,
        &branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (branch_page.table_id != table_id ||
        branch_page.index_number != delete_entry->index_number || branch_page.level != 1U ||
        branch_page.entry_count == 0ULL || branch_page.child_count == 0U ||
        delete_entry->child_index >= branch_page.child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page.key_size;
    const unsigned char *branch_cell =
        branch_page.payload + (delete_entry->child_index * branch_cell_size);
    if (get_u64_le(branch_cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET) !=
        delete_entry->leaf_page_id) {
        return MYLITE_STORAGE_CORRUPT;
    }

    unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = pager_read_page(pager, delete_entry->leaf_page_id, leaf_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    mylite_storage_index_leaf_page leaf_page = {0};
    result =
        decode_index_leaf_page(header, delete_entry->leaf_page_id, leaf_page_bytes, &leaf_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != delete_entry->index_number ||
        leaf_page.key_size != branch_page.key_size || leaf_page.entry_count <= 1U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    result = delete_index_leaf_entry(leaf_page_bytes, header, delete_entry->leaf_page_id, row_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    result = refresh_index_branch_child_after_leaf_delete(
        branch_page_bytes,
        header,
        delete_entry->root_page_id,
        &branch_page,
        delete_entry->leaf_page_id,
        leaf_page_bytes
    );
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, delete_entry->leaf_page_id, leaf_page_bytes);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, delete_entry->root_page_id, branch_page_bytes);
    }
    return result;
}

static mylite_storage_result remove_branch_index_child_entry(
    const mylite_storage_pager *pager,
    mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long row_id,
    const mylite_storage_branch_index_delete *delete_entry
) {
    unsigned char branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result =
        pager_read_page(pager, delete_entry->root_page_id, branch_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_branch_page branch_page = {0};
    result = decode_index_branch_page(
        header,
        delete_entry->root_page_id,
        branch_page_bytes,
        &branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (branch_page.table_id != table_id ||
        branch_page.index_number != delete_entry->index_number || branch_page.level != 1U ||
        branch_page.entry_count <= 1ULL || branch_page.child_count <= 1U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page.key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const unsigned long long current_expected_child_count =
        ((branch_page.entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    const unsigned long long new_entry_count = branch_page.entry_count - 1ULL;
    const unsigned long long expected_child_count =
        ((new_entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (current_expected_child_count != (unsigned long long)branch_page.child_count ||
        expected_child_count + 1ULL != (unsigned long long)branch_page.child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page.key_size;
    if (delete_entry->child_index >= branch_page.child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const unsigned char *removed_cell =
        branch_page.payload + (delete_entry->child_index * branch_cell_size);
    if (get_u64_le(removed_cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET) !=
        delete_entry->leaf_page_id) {
        return MYLITE_STORAGE_CORRUPT;
    }

    unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = pager_read_page(pager, delete_entry->leaf_page_id, leaf_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    mylite_storage_index_leaf_page leaf_page = {0};
    result =
        decode_index_leaf_page(header, delete_entry->leaf_page_id, leaf_page_bytes, &leaf_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != delete_entry->index_number ||
        leaf_page.key_size != branch_page.key_size || leaf_page.entry_count != 1U ||
        index_leaf_entry_row_id(&leaf_page, 0U) != row_id) {
        return MYLITE_STORAGE_CORRUPT;
    }

    int collapsed = 0;
    result = try_collapse_branch_index_root_after_child_removal(
        pager,
        header,
        branch_page_bytes,
        delete_entry->root_page_id,
        &branch_page,
        delete_entry->child_index,
        table_id,
        row_id,
        &collapsed
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (collapsed) {
        result = pager_write_page(pager, delete_entry->root_page_id, branch_page_bytes);
        if (result == MYLITE_STORAGE_OK) {
            result = reclaim_removed_branch_leaf_page_for_delete(
                pager,
                header,
                delete_entry->leaf_page_id
            );
        }
        return result;
    }

    const size_t new_child_count = branch_page.child_count - 1U;
    unsigned char *payload = branch_page_bytes + MYLITE_STORAGE_FORMAT_INDEX_BRANCH_PAYLOAD_OFFSET;
    const size_t removed_cell_offset = delete_entry->child_index * branch_cell_size;
    const size_t bytes_after_removed_cell =
        (branch_page.child_count - delete_entry->child_index - 1U) * branch_cell_size;
    if (bytes_after_removed_cell != 0U) {
        memmove(
            payload + removed_cell_offset,
            payload + removed_cell_offset + branch_cell_size,
            bytes_after_removed_cell
        );
    }
    const size_t used_bytes =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_PAYLOAD_OFFSET + (new_child_count * branch_cell_size);
    memset(branch_page_bytes + used_bytes, 0, branch_page.used_bytes - used_bytes);
    put_u32_le(
        branch_page_bytes,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHILD_COUNT_OFFSET,
        (unsigned)new_child_count
    );
    put_u32_le(
        branch_page_bytes,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_USED_BYTES_OFFSET,
        (unsigned)used_bytes
    );
    put_u64_le(
        branch_page_bytes,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_ENTRY_COUNT_OFFSET,
        new_entry_count
    );
    put_u64_le(branch_page_bytes, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET, 0ULL);
    put_u64_le(
        branch_page_bytes,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET,
        checksum_page_zero_tail(
            branch_page_bytes,
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET,
            used_bytes
        )
    );

    mylite_storage_index_branch_page updated_branch_page = {0};
    result = decode_index_branch_page(
        header,
        delete_entry->root_page_id,
        branch_page_bytes,
        &updated_branch_page
    );
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, delete_entry->root_page_id, branch_page_bytes);
    }
    if (result == MYLITE_STORAGE_OK) {
        result =
            reclaim_removed_branch_leaf_page_for_delete(pager, header, delete_entry->leaf_page_id);
    }
    return result;
}

static mylite_storage_result collapse_branch_index_child_count_delete_entry(
    const mylite_storage_pager *pager,
    mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long row_id,
    const mylite_storage_branch_index_delete *delete_entry
) {
    unsigned char branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result =
        pager_read_page(pager, delete_entry->root_page_id, branch_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_branch_page branch_page = {0};
    result = decode_index_branch_page(
        header,
        delete_entry->root_page_id,
        branch_page_bytes,
        &branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (branch_page.table_id != table_id ||
        branch_page.index_number != delete_entry->index_number || branch_page.level != 1U ||
        branch_page.entry_count <= 1ULL || branch_page.child_count <= 1U ||
        branch_page.child_count > MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN ||
        delete_entry->child_index >= branch_page.child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page.key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const unsigned long long current_expected_child_count =
        ((branch_page.entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    const unsigned long long new_entry_count = branch_page.entry_count - 1ULL;
    const unsigned long long expected_child_count =
        ((new_entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (current_expected_child_count != (unsigned long long)branch_page.child_count ||
        expected_child_count + 1ULL != (unsigned long long)branch_page.child_count ||
        new_entry_count > maintained_index_root_entry_capacity(branch_page.key_size)) {
        return MYLITE_STORAGE_CORRUPT;
    }
    int has_live_overlay = 0;
    result = index_branch_tail_has_live_overlay(
        pager->file,
        header,
        table_id,
        delete_entry->index_number,
        &branch_page,
        &has_live_overlay
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (has_live_overlay) {
        return MYLITE_STORAGE_CORRUPT;
    }

    unsigned long long child_page_ids[MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN] = {0};
    mylite_storage_index_entryset entries = {
        .size = sizeof(entries),
    };
    int source_child_contains_row = 0;
    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page.key_size;
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < branch_page.child_count; ++i) {
        const unsigned char *cell = branch_page.payload + (i * branch_cell_size);
        child_page_ids[i] =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);

        unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        result = pager_read_page(pager, child_page_ids[i], leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            break;
        }
        mylite_storage_index_leaf_page leaf_page = {0};
        result = decode_index_leaf_page(header, child_page_ids[i], leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            break;
        }
        if (leaf_page.table_id != table_id ||
            leaf_page.index_number != delete_entry->index_number ||
            leaf_page.key_size != branch_page.key_size) {
            result = MYLITE_STORAGE_CORRUPT;
            break;
        }
        if (i == delete_entry->child_index) {
            if (child_page_ids[i] != delete_entry->leaf_page_id || leaf_page.entry_count <= 1U) {
                result = MYLITE_STORAGE_CORRUPT;
                break;
            }
            for (size_t leaf_entry = 0U; leaf_entry < leaf_page.entry_count; ++leaf_entry) {
                if (index_leaf_entry_row_id(&leaf_page, leaf_entry) == row_id) {
                    source_child_contains_row = 1;
                    break;
                }
            }
        }
        result = append_index_leaf_entries_to_entryset(&leaf_page, &entries);
    }
    if (result == MYLITE_STORAGE_OK && !source_child_contains_row) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK &&
        (unsigned long long)entries.entry_count != branch_page.entry_count) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    const size_t before_remove_count = entries.entry_count;
    if (result == MYLITE_STORAGE_OK) {
        remove_index_entries_by_row_id(&entries, row_id);
        if (entries.entry_count + 1U != before_remove_count ||
            (unsigned long long)entries.entry_count != new_entry_count) {
            result = MYLITE_STORAGE_CORRUPT;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = encode_maintained_index_root_page_from_entryset(
            branch_page_bytes,
            delete_entry->root_page_id,
            table_id,
            delete_entry->index_number,
            branch_page.key_size,
            &entries
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, delete_entry->root_page_id, branch_page_bytes);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = reclaim_removed_branch_leaf_page_for_delete(
            pager,
            header,
            child_page_ids[branch_page.child_count - 1U]
        );
    }

    mylite_storage_free_index_entryset(&entries);
    return result;
}

static mylite_storage_result refold_branch_index_child_count_delete_entry(
    const mylite_storage_pager *pager,
    mylite_storage_header *header,
    unsigned long long table_id,
    unsigned long long row_id,
    const mylite_storage_branch_index_delete *delete_entry
) {
    unsigned char branch_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result =
        pager_read_page(pager, delete_entry->root_page_id, branch_page_bytes);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_branch_page branch_page = {0};
    result = decode_index_branch_page(
        header,
        delete_entry->root_page_id,
        branch_page_bytes,
        &branch_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (branch_page.table_id != table_id ||
        branch_page.index_number != delete_entry->index_number || branch_page.level != 1U ||
        branch_page.entry_count <= 1ULL || branch_page.child_count <= 1U ||
        branch_page.child_count > MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN ||
        delete_entry->child_index >= branch_page.child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page.key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const unsigned long long current_expected_child_count =
        ((branch_page.entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    const unsigned long long new_entry_count = branch_page.entry_count - 1ULL;
    const unsigned long long expected_child_count =
        ((new_entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (current_expected_child_count != (unsigned long long)branch_page.child_count ||
        expected_child_count + 1ULL != (unsigned long long)branch_page.child_count ||
        expected_child_count == 0ULL ||
        expected_child_count > (unsigned long long)MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN ||
        new_entry_count <= maintained_index_root_entry_capacity(branch_page.key_size)) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const size_t updated_child_count = (size_t)expected_child_count;

    unsigned long long child_page_ids[MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN] = {0};
    mylite_storage_index_entryset entries = {
        .size = sizeof(entries),
    };
    int source_child_contains_row = 0;
    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page.key_size;
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < branch_page.child_count; ++i) {
        const unsigned char *cell = branch_page.payload + (i * branch_cell_size);
        child_page_ids[i] =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);

        unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        result = pager_read_page(pager, child_page_ids[i], leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            break;
        }
        mylite_storage_index_leaf_page leaf_page = {0};
        result = decode_index_leaf_page(header, child_page_ids[i], leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            break;
        }
        if (leaf_page.table_id != table_id ||
            leaf_page.index_number != delete_entry->index_number ||
            leaf_page.key_size != branch_page.key_size) {
            result = MYLITE_STORAGE_CORRUPT;
            break;
        }
        if (i == delete_entry->child_index) {
            if (child_page_ids[i] != delete_entry->leaf_page_id || leaf_page.entry_count <= 1U) {
                result = MYLITE_STORAGE_CORRUPT;
                break;
            }
            for (size_t leaf_entry = 0U; leaf_entry < leaf_page.entry_count; ++leaf_entry) {
                if (index_leaf_entry_row_id(&leaf_page, leaf_entry) == row_id) {
                    source_child_contains_row = 1;
                    break;
                }
            }
        }
        result = append_index_leaf_entries_to_entryset(&leaf_page, &entries);
    }
    if (result == MYLITE_STORAGE_OK && !source_child_contains_row) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK &&
        (unsigned long long)entries.entry_count != branch_page.entry_count) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    const size_t before_remove_count = entries.entry_count;
    if (result == MYLITE_STORAGE_OK) {
        remove_index_entries_by_row_id(&entries, row_id);
        if (entries.entry_count + 1U != before_remove_count ||
            (unsigned long long)entries.entry_count != new_entry_count) {
            result = MYLITE_STORAGE_CORRUPT;
        }
    }

    size_t key_size = 0U;
    size_t *order = NULL;
    if (result == MYLITE_STORAGE_OK) {
        result = index_entryset_fixed_key_size(&entries, &key_size);
    }
    if (result == MYLITE_STORAGE_OK && key_size != branch_page.key_size) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = build_raw_index_entry_order(&entries, &order);
    }

    unsigned char *updated_leaf_pages = NULL;
    unsigned long long child_max_row_ids[MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN] = {0};
    unsigned char *child_max_keys = NULL;
    if (result == MYLITE_STORAGE_OK) {
        if (updated_child_count > SIZE_MAX / MYLITE_STORAGE_FORMAT_PAGE_SIZE ||
            updated_child_count > SIZE_MAX / branch_page.key_size) {
            result = MYLITE_STORAGE_FULL;
        } else {
            updated_leaf_pages =
                (unsigned char *)malloc(updated_child_count * MYLITE_STORAGE_FORMAT_PAGE_SIZE);
            child_max_keys = (unsigned char *)malloc(updated_child_count * branch_page.key_size);
            if (updated_leaf_pages == NULL || child_max_keys == NULL) {
                result = MYLITE_STORAGE_NOMEM;
            }
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        const size_t leaf_cell_size =
            MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE + branch_page.key_size;
        size_t first_entry = 0U;
        for (size_t i = 0U; i < updated_child_count; ++i) {
            const size_t remaining_entries = entries.entry_count - first_entry;
            const size_t leaf_entry_count =
                remaining_entries > leaf_capacity ? leaf_capacity : remaining_entries;
            if (leaf_entry_count == 0U) {
                result = MYLITE_STORAGE_CORRUPT;
                break;
            }

            unsigned char *leaf_page = updated_leaf_pages + (i * MYLITE_STORAGE_FORMAT_PAGE_SIZE);
            encode_index_leaf_page(
                leaf_page,
                child_page_ids[i],
                table_id,
                delete_entry->index_number,
                &entries,
                order,
                first_entry,
                leaf_entry_count,
                branch_page.key_size,
                MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET +
                    (leaf_entry_count * leaf_cell_size)
            );
            read_encoded_index_leaf_max_cell(
                leaf_page,
                branch_page.key_size,
                child_max_row_ids + i,
                child_max_keys + (i * branch_page.key_size)
            );
            first_entry += leaf_entry_count;
        }
        if (result == MYLITE_STORAGE_OK && first_entry != entries.entry_count) {
            result = MYLITE_STORAGE_CORRUPT;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = encode_index_branch_page(
            branch_page_bytes,
            delete_entry->root_page_id,
            table_id,
            delete_entry->index_number,
            1U,
            branch_page.key_size,
            new_entry_count,
            child_page_ids,
            child_max_row_ids,
            child_max_keys,
            updated_child_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        mylite_storage_index_branch_page updated_branch_page = {0};
        result = decode_index_branch_page(
            header,
            delete_entry->root_page_id,
            branch_page_bytes,
            &updated_branch_page
        );
    }
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < updated_child_count; ++i) {
        result = pager_write_page(
            pager,
            child_page_ids[i],
            updated_leaf_pages + (i * MYLITE_STORAGE_FORMAT_PAGE_SIZE)
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = pager_write_page(pager, delete_entry->root_page_id, branch_page_bytes);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = reclaim_removed_branch_leaf_page_for_delete(
            pager,
            header,
            child_page_ids[updated_child_count]
        );
    }

    free(child_max_keys);
    free(updated_leaf_pages);
    free(order);
    mylite_storage_free_index_entryset(&entries);
    return result;
}

static mylite_storage_result try_collapse_branch_index_root_after_child_removal(
    const mylite_storage_pager *pager,
    const mylite_storage_header *header,
    unsigned char *branch_page_bytes,
    unsigned long long branch_page_id,
    const mylite_storage_index_branch_page *branch_page,
    size_t removed_child_index,
    unsigned long long table_id,
    unsigned long long row_id,
    int *out_collapsed
) {
    *out_collapsed = 0;

    mylite_storage_index_entryset entries = {
        .size = sizeof(entries),
    };
    mylite_storage_result result = MYLITE_STORAGE_OK;
    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    unsigned long long max_child_page_id = 0ULL;
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < branch_page->child_count; ++i) {
        if (i == removed_child_index) {
            continue;
        }
        const unsigned char *cell = branch_page->payload + (i * branch_cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (child_page_id > max_child_page_id) {
            max_child_page_id = child_page_id;
        }

        unsigned char leaf_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        result = pager_read_page(pager, child_page_id, leaf_page_bytes);
        if (result != MYLITE_STORAGE_OK) {
            break;
        }
        mylite_storage_index_leaf_page leaf_page = {0};
        result = decode_index_leaf_page(header, child_page_id, leaf_page_bytes, &leaf_page);
        if (result != MYLITE_STORAGE_OK) {
            break;
        }
        if (leaf_page.table_id != table_id || leaf_page.index_number != branch_page->index_number ||
            leaf_page.key_size != branch_page->key_size) {
            result = MYLITE_STORAGE_CORRUPT;
            break;
        }
        result = append_index_leaf_entries_to_entryset(&leaf_page, &entries);
    }
    if (result == MYLITE_STORAGE_OK && max_child_page_id == ULLONG_MAX) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = read_live_index_entries_from(
            pager->file,
            header,
            table_id,
            branch_page->index_number,
            max_child_page_id + 1ULL,
            &entries
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        remove_index_entries_by_row_id(&entries, row_id);
        const size_t root_capacity = maintained_index_root_entry_capacity(branch_page->key_size);
        if (entries.entry_count != 0U && entries.entry_count <= root_capacity) {
            result = encode_maintained_index_root_page_from_entryset(
                branch_page_bytes,
                branch_page_id,
                table_id,
                branch_page->index_number,
                branch_page->key_size,
                &entries
            );
            if (result == MYLITE_STORAGE_OK) {
                *out_collapsed = 1;
            }
        }
    }

    mylite_storage_free_index_entryset(&entries);
    return result;
}

static mylite_storage_result reclaim_removed_branch_leaf_page_for_delete(
    const mylite_storage_pager *pager,
    mylite_storage_header *header,
    unsigned long long leaf_page_id
) {
    if (header->page_count != 0ULL && leaf_page_id == header->page_count - 1ULL) {
        header->page_count = leaf_page_id;
        return MYLITE_STORAGE_OK;
    }
    return reclaim_removed_branch_leaf_page(pager, header, leaf_page_id);
}

static mylite_storage_result reclaim_removed_branch_leaf_page(
    const mylite_storage_pager *pager,
    mylite_storage_header *header,
    unsigned long long leaf_page_id
) {
    mylite_storage_free_list_reclaim_plan plan = {0};
    mylite_storage_result result =
        plan_reclaimed_free_list_run(pager->file, header, leaf_page_id, 1ULL, &plan);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    result = write_free_list_reclaim_plan(pager, &plan);
    if (result == MYLITE_STORAGE_OK) {
        header->free_list_root_page = plan.root_page_id;
    }
    return result;
}

static mylite_storage_result delete_index_leaf_entry(
    unsigned char *page,
    const mylite_storage_header *header,
    unsigned long long page_id,
    unsigned long long row_id
) {
    mylite_storage_index_leaf_page leaf_page = {0};
    mylite_storage_result result = decode_index_leaf_page(header, page_id, page, &leaf_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE + leaf_page.key_size;
    unsigned char *payload = page + MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET;
    size_t write_index = 0U;
    for (size_t read_index = 0U; read_index < leaf_page.entry_count; ++read_index) {
        unsigned char *source = payload + (read_index * cell_size);
        if (get_u64_le(source, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET) == row_id) {
            continue;
        }
        if (write_index != read_index) {
            memmove(payload + (write_index * cell_size), source, cell_size);
        }
        ++write_index;
    }
    if (write_index == leaf_page.entry_count || write_index == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t old_used_bytes = leaf_page.used_bytes;
    const size_t used_bytes =
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET + (write_index * cell_size);
    memset(page + used_bytes, 0, old_used_bytes - used_bytes);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_COUNT_OFFSET, (unsigned)write_index);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_USED_BYTES_OFFSET, (unsigned)used_bytes);
    put_u64_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET, 0ULL);
    put_u64_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET,
        checksum_page_zero_tail(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET, used_bytes)
    );
    return decode_index_leaf_page(header, page_id, page, &leaf_page);
}

static mylite_storage_result refresh_index_branch_child_after_leaf_delete(
    unsigned char *branch_page_bytes,
    const mylite_storage_header *header,
    unsigned long long branch_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long leaf_page_id,
    const unsigned char *leaf_page
) {
    const size_t leaf_entry_count =
        get_u32_le(leaf_page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_COUNT_OFFSET);
    if (leaf_entry_count == 0U || branch_page->entry_count <= 1ULL) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const size_t leaf_capacity = index_leaf_entry_capacity(branch_page->key_size);
    if (leaf_capacity == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const unsigned long long new_entry_count = branch_page->entry_count - 1ULL;
    const unsigned long long expected_child_count =
        ((new_entry_count - 1ULL) / (unsigned long long)leaf_capacity) + 1ULL;
    if (expected_child_count != (unsigned long long)branch_page->child_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t leaf_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE + branch_page->key_size;
    const unsigned char *leaf_cell = leaf_page + MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET +
                                     ((leaf_entry_count - 1U) * leaf_cell_size);
    const size_t branch_cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    unsigned char *branch_cell = NULL;
    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        unsigned char *candidate = branch_page_bytes +
                                   MYLITE_STORAGE_FORMAT_INDEX_BRANCH_PAYLOAD_OFFSET +
                                   (i * branch_cell_size);
        const unsigned long long child_page_id =
            get_u64_le(candidate, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (child_page_id == leaf_page_id) {
            branch_cell = candidate;
            break;
        }
    }
    if (branch_cell == NULL) {
        return MYLITE_STORAGE_CORRUPT;
    }

    put_u64_le(
        branch_cell,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_ROW_ID_OFFSET,
        get_u64_le(leaf_cell, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET)
    );
    memcpy(
        branch_cell + MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_KEY_OFFSET,
        leaf_cell + MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET,
        branch_page->key_size
    );
    put_u64_le(
        branch_page_bytes,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_ENTRY_COUNT_OFFSET,
        branch_page->entry_count - 1ULL
    );
    put_u64_le(branch_page_bytes, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET, 0ULL);
    put_u64_le(
        branch_page_bytes,
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET,
        checksum_page_zero_tail(
            branch_page_bytes,
            MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET,
            branch_page->used_bytes
        )
    );

    mylite_storage_index_branch_page updated_branch_page = {0};
    return decode_index_branch_page(
        header,
        branch_page_id,
        branch_page_bytes,
        &updated_branch_page
    );
}

static mylite_storage_result refill_maintained_index_root_from_overflow_tail(
    FILE *file,
    const mylite_storage_header *header,
    unsigned long long page_id,
    unsigned char *page
) {
    mylite_storage_maintained_index_root_page root_page = {0};
    mylite_storage_result result =
        decode_maintained_index_root_page(header, page_id, page, &root_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if ((root_page.flags & MYLITE_STORAGE_FORMAT_INDEX_ROOT_FLAG_HAS_OVERFLOW_TAIL) == 0U) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_index_leaf_page leaf_page = {0};
    maintained_index_root_page_as_leaf_page(&root_page, &leaf_page);
    mylite_storage_index_entryset entries = {
        .size = sizeof(entries),
    };
    result = append_index_leaf_entries_to_entryset(&leaf_page, &entries);
    if (result == MYLITE_STORAGE_OK) {
        result = read_live_index_entries_from(
            file,
            header,
            root_page.table_id,
            root_page.index_number,
            maintained_index_root_tail_page_id(&root_page, page_id),
            &entries
        );
    }
    if (result == MYLITE_STORAGE_OK &&
        entries.entry_count <= maintained_index_root_entry_capacity(root_page.key_size)) {
        result = encode_maintained_index_root_page_from_entryset(
            page,
            page_id,
            root_page.table_id,
            root_page.index_number,
            root_page.key_size,
            &entries
        );
    }
    mylite_storage_free_index_entryset(&entries);
    return result;
}

static mylite_storage_result mark_maintained_index_root_overflow_tail(
    unsigned char *page,
    const mylite_storage_header *header,
    unsigned long long page_id,
    unsigned long long first_fallback_index_page_id
) {
    mylite_storage_maintained_index_root_page root_page = {0};
    mylite_storage_result result =
        decode_maintained_index_root_page(header, page_id, page, &root_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if ((root_page.flags & MYLITE_STORAGE_FORMAT_INDEX_ROOT_FLAG_HAS_OVERFLOW_TAIL) != 0U) {
        return MYLITE_STORAGE_OK;
    }
    if (first_fallback_index_page_id <= page_id) {
        return MYLITE_STORAGE_CORRUPT;
    }

    put_u32_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_FLAGS_OFFSET,
        root_page.flags | MYLITE_STORAGE_FORMAT_INDEX_ROOT_FLAG_HAS_OVERFLOW_TAIL
    );
    put_u64_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_OVERFLOW_TAIL_PAGE_OFFSET,
        first_fallback_index_page_id
    );
    put_u64_le(page, MYLITE_STORAGE_FORMAT_INDEX_ROOT_CHECKSUM_OFFSET, 0ULL);
    put_u64_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_CHECKSUM_OFFSET,
        checksum_page_zero_tail(
            page,
            MYLITE_STORAGE_FORMAT_INDEX_ROOT_CHECKSUM_OFFSET,
            root_page.used_bytes
        )
    );
    return MYLITE_STORAGE_OK;
}

static int maintained_index_root_page_has_row_id(
    const mylite_storage_maintained_index_root_page *root_page,
    unsigned long long row_id
) {
    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_HEADER_SIZE + root_page->key_size;
    for (size_t i = 0U; i < root_page->entry_count; ++i) {
        const unsigned char *cell = root_page->payload + (i * cell_size);
        if (get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_ROOT_ENTRY_ROW_ID_OFFSET) == row_id) {
            return 1;
        }
    }
    return 0;
}

mylite_storage_result mylite_storage_truncate_table(
    const char *filename,
    const char *schema_name,
    const char *table_name
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_update_file_scope file_scope = {0};
    mylite_storage_result result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;
    mylite_storage_statement *active_cache_statement =
        active_cache_statement_from_statement(file_scope.active_statement);

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    unsigned long long table_id = 0ULL;
    mylite_storage_row_id_list live_rows = {0};
    mylite_storage_truncate_index_root_reset *index_root_resets = NULL;
    size_t index_root_reset_count = 0U;
    unsigned long long current_next_value = 0ULL;
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_id_in_statement(
            file,
            &header,
            active_cache_statement,
            schema_name,
            table_name,
            &table_id
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = collect_truncate_index_root_resets(
            file,
            &header,
            &catalog,
            table_id,
            &index_root_resets,
            &index_root_reset_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = scan_table_row_pages(file, &header, table_id, append_live_row_id, &live_rows);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = latest_auto_increment_value(file, &header, table_id, &current_next_value);
    }

    const int reset_auto_increment = current_next_value != 1ULL;
    if (result == MYLITE_STORAGE_OK &&
        truncate_needs_publication(&live_rows, reset_auto_increment, index_root_reset_count)) {
        result = write_truncate_publication(
            file,
            filename,
            &header,
            file_scope.active_statement,
            table_id,
            &live_rows,
            reset_auto_increment,
            index_root_resets,
            index_root_reset_count
        );
    }

    free_catalog_image(&catalog);
    free(index_root_resets);
    free(live_rows.row_ids);
    if (result == MYLITE_STORAGE_OK) {
        invalidate_exact_index_caches(filename);
    }
    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

mylite_storage_result mylite_storage_read_index_entries(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    unsigned index_number,
    mylite_storage_index_entryset *out_entries
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0' || out_entries == NULL ||
        out_entries->size < sizeof(*out_entries)) {
        return MYLITE_STORAGE_MISUSE;
    }

    *out_entries = (mylite_storage_index_entryset){
        .size = sizeof(*out_entries),
    };

    mylite_storage_file_scope file_scope = {0};
    mylite_storage_result result = open_existing_file_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    int has_catalog = 0;
    mylite_storage_catalog_entry table_entry = {0};
    int used_leaf = 0;
    mylite_storage_statement *active_cache_statement =
        active_cache_statement_from_statement(file_scope.active_statement);
    mylite_storage_statement *complete_entryset_cache_statement = NULL;
    if (active_cache_statement == NULL) {
        active_cache_statement =
            active_cache_statement_from_statement(file_scope.active_read_statement);
    }
    if (file_scope.active_statement == NULL) {
        complete_entryset_cache_statement =
            active_cache_statement_from_statement(file_scope.active_read_statement);
    }
    result = read_header_from_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        const int used_cached_table_entry = find_active_table_entry_cache_in_statement(
            active_cache_statement,
            &header,
            schema_name,
            table_name,
            &table_entry
        );
        if (!used_cached_table_entry) {
            result = read_catalog_image(file, &header, &catalog);
            if (result == MYLITE_STORAGE_OK) {
                has_catalog = 1;
                result = find_table_record(&catalog, schema_name, table_name, &table_entry);
            }
            if (result == MYLITE_STORAGE_OK) {
                store_active_table_entry_cache_in_statement(
                    active_cache_statement,
                    &header,
                    schema_name,
                    table_name,
                    &table_entry
                );
            }
        }
    }
    if (result == MYLITE_STORAGE_OK && !has_catalog) {
        result = read_catalog_image(file, &header, &catalog);
        if (result == MYLITE_STORAGE_OK) {
            has_catalog = 1;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = read_index_leaf_entries(
            file,
            filename,
            &header,
            active_cache_statement,
            &catalog,
            table_entry.table_id,
            schema_name,
            table_name,
            index_number,
            out_entries,
            &used_leaf
        );
    }
    if (result == MYLITE_STORAGE_OK && !used_leaf) {
        int used_cache = 0;
        const int allow_durable_cache =
            file_scope.active_statement == NULL && file_scope.active_read_snapshot == NULL;
        result = append_cached_complete_index_entries(
            filename,
            &header,
            complete_entryset_cache_statement,
            allow_durable_cache,
            table_entry.table_id,
            index_number,
            out_entries,
            &used_cache
        );
        if (result == MYLITE_STORAGE_OK && !used_cache) {
            result = read_live_index_entries(
                file,
                &header,
                table_entry.table_id,
                index_number,
                out_entries
            );
            if (result == MYLITE_STORAGE_OK) {
                result = cache_complete_index_entries(
                    filename,
                    &header,
                    complete_entryset_cache_statement,
                    allow_durable_cache,
                    table_entry.table_id,
                    index_number,
                    out_entries
                );
            }
        }
    }
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < out_entries->entry_count; ++i) {
        (void)mark_active_live_row(file, &header, table_entry.table_id, out_entries->row_ids[i]);
    }

    if (close_existing_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    free_catalog_image(&catalog);
    if (result != MYLITE_STORAGE_OK) {
        mylite_storage_free_index_entryset(out_entries);
    }
    return result;
}

