static char *copy_string(const char *value) {
    const size_t value_size = strlen(value) + 1U;
    char *copy = (char *)malloc(value_size);
    if (copy == NULL) {
        return NULL;
    }

    memcpy(copy, value, value_size);
    return copy;
}

static char *copy_filename(const char *filename) {
    return copy_string(filename);
}

static mylite_storage_result read_header_from_file_scope(
    const mylite_storage_file_scope *scope,
    mylite_storage_header *out_header
) {
    if (scope == NULL || scope->file == NULL || out_header == NULL) {
        return MYLITE_STORAGE_MISUSE;
    }
    if (scope->active_statement != NULL && scope->active_statement->has_current_header) {
        *out_header = scope->active_statement->current_header;
        return MYLITE_STORAGE_OK;
    }
    if (scope->active_read_statement != NULL) {
        *out_header = scope->active_read_statement->header;
        return MYLITE_STORAGE_OK;
    }
    if (scope->active_read_snapshot != NULL) {
        *out_header = scope->active_read_snapshot->header;
        return MYLITE_STORAGE_OK;
    }
    if (active_transaction_journal_snapshot_has_file(scope->file)) {
        *out_header = active_transaction_journal_snapshot.header;
        return MYLITE_STORAGE_OK;
    }
    return read_header(scope->file, out_header);
}

static mylite_storage_result read_header_from_update_file_scope(
    const mylite_storage_update_file_scope *scope,
    mylite_storage_header *out_header
) {
    if (scope == NULL || scope->file == NULL || out_header == NULL) {
        return MYLITE_STORAGE_MISUSE;
    }
    if (scope->active_statement != NULL && scope->active_statement->has_current_header) {
        *out_header = scope->active_statement->current_header;
        return MYLITE_STORAGE_OK;
    }
    if (scope->active_read_statement != NULL) {
        *out_header = scope->active_read_statement->header;
        return MYLITE_STORAGE_OK;
    }
    if (active_transaction_journal_snapshot_has_file(scope->file)) {
        *out_header = active_transaction_journal_snapshot.header;
        return MYLITE_STORAGE_OK;
    }
    return read_header(scope->file, out_header);
}

static mylite_storage_result read_header(FILE *file, mylite_storage_header *out_header) {
    mylite_storage_statement *statement = active_statement_for_file(file);
    if (statement != NULL && statement->has_current_header) {
        *out_header = statement->current_header;
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_statement *read_statement = active_read_statement_for_file(file);
    if (read_statement != NULL) {
        *out_header = read_statement->header;
        return MYLITE_STORAGE_OK;
    }

    if (active_read_snapshot_has_file(file)) {
        *out_header = active_read_snapshot->header;
        return MYLITE_STORAGE_OK;
    }

    if (active_transaction_journal_snapshot_has_file(file)) {
        *out_header = active_transaction_journal_snapshot.header;
        return MYLITE_STORAGE_OK;
    }

    unsigned char header_page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result = read_page_at(
        file,
        MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID,
        MYLITE_STORAGE_FORMAT_PAGE_SIZE,
        header_page
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    return decode_header_page(header_page, out_header);
}

static mylite_storage_result read_page_at(
    FILE *file,
    unsigned long long page_id,
    unsigned page_size,
    unsigned char *out_page
) {
    mylite_storage_statement *statement = active_statement_for_file(file);
    if (statement != NULL && statement->has_current_header &&
        page_id == MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID &&
        page_size == MYLITE_STORAGE_FORMAT_PAGE_SIZE) {
        encode_header_page(out_page, &statement->current_header);
        return MYLITE_STORAGE_OK;
    }
    if (copy_dirty_page_buffer(statement, page_id, page_size, out_page)) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_statement *read_statement = active_read_statement_for_file(file);
    if (read_statement != NULL) {
        if (page_id == MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID &&
            page_size == MYLITE_STORAGE_FORMAT_PAGE_SIZE) {
            materialize_statement_header_page(read_statement);
            memcpy(out_page, read_statement->header_page, page_size);
            return MYLITE_STORAGE_OK;
        }
        if (read_statement->has_current_catalog_page &&
            page_id == read_statement->current_catalog_root_page &&
            page_size == read_statement->header.page_size) {
            memcpy(out_page, read_statement->current_catalog_page, page_size);
            return MYLITE_STORAGE_OK;
        }
        if (copy_read_statement_transaction_snapshot_page(
                read_statement,
                page_id,
                page_size,
                out_page
            )) {
            return MYLITE_STORAGE_OK;
        }
    }

    if (active_read_snapshot_has_file(file)) {
        if (page_id == MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID &&
            page_size == MYLITE_STORAGE_FORMAT_PAGE_SIZE) {
            memcpy(out_page, active_read_snapshot->header_page, page_size);
            return MYLITE_STORAGE_OK;
        }
        if (page_id == active_read_snapshot->header.catalog_root_page &&
            page_size == active_read_snapshot->header.page_size) {
            memcpy(out_page, active_read_snapshot->catalog_page, page_size);
            return MYLITE_STORAGE_OK;
        }
    }

    if (active_transaction_journal_snapshot_has_file(file)) {
        if (copy_transaction_journal_snapshot_page(file, page_id, page_size, out_page)) {
            return MYLITE_STORAGE_OK;
        }
    }

    int copied_buffered_page = 0;
    mylite_storage_result result =
        copy_buffered_append_page(file, page_id, page_size, out_page, &copied_buffered_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (copied_buffered_page) {
        return MYLITE_STORAGE_OK;
    }

    off_t offset = 0;
    result = page_offset_for_io(page_id, page_size, &offset);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    return read_file_at(file, offset, out_page, page_size);
}

static int copy_read_statement_transaction_snapshot_page(
    const mylite_storage_statement *statement,
    unsigned long long page_id,
    size_t page_size,
    unsigned char *out_page
) {
    if (statement == NULL || statement->transaction_snapshot_page_count == 0U) {
        return 0;
    }
    for (size_t i = 0U; i < statement->transaction_snapshot_page_count; ++i) {
        if (statement->transaction_snapshot_page_ids[i] != page_id) {
            continue;
        }
        if (page_id == MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID) {
            if (page_size != MYLITE_STORAGE_FORMAT_PAGE_SIZE) {
                return 0;
            }
        } else if (page_size != statement->header.page_size) {
            return 0;
        }
        memcpy(out_page, statement->transaction_snapshot_pages[i], page_size);
        return 1;
    }
    return 0;
}

static mylite_storage_pager open_storage_pager(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header
) {
    return (mylite_storage_pager){
        .file = file,
        .filename = filename,
        .header = header,
    };
}

static mylite_storage_result pager_read_page(
    const mylite_storage_pager *pager,
    unsigned long long page_id,
    unsigned char *out_page
) {
    return read_page_at(pager->file, page_id, pager->header->page_size, out_page);
}

static mylite_storage_result pager_write_page(
    const mylite_storage_pager *pager,
    unsigned long long page_id,
    const unsigned char *page
) {
    mylite_storage_result result = capture_dirty_page_undo_for_pager_write(pager, page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    result = write_page_at(pager->file, page_id, pager->header->page_size, page);
    if (result == MYLITE_STORAGE_OK) {
        store_active_index_leaf_page_from_pager_write(pager, page_id, page);
        store_active_index_branch_page_from_pager_write(pager, page_id, page);
        discard_dirty_page_buffer_entry_in_statement_chain(
            active_statement_for_file(pager->file),
            page_id
        );
    }
    return result;
}

static mylite_storage_result pager_write_prevalidated_index_leaf_page(
    const mylite_storage_pager *pager,
    unsigned long long page_id,
    const unsigned char *page
) {
    mylite_storage_result result = capture_dirty_page_undo_for_pager_write(pager, page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    result = write_page_at(pager->file, page_id, pager->header->page_size, page);
    if (result == MYLITE_STORAGE_OK) {
        store_active_index_leaf_page_from_encoded_page(pager->file, page_id, page);
        discard_dirty_page_buffer_entry_in_statement_chain(
            active_statement_for_file(pager->file),
            page_id
        );
    }
    return result;
}

static mylite_storage_result pager_write_maintained_insert_page(
    const mylite_storage_pager *pager,
    unsigned long long page_id,
    const unsigned char *page,
    int buffer_existing_page
) {
    if (!buffer_existing_page) {
        return pager_write_page(pager, page_id, page);
    }
    return pager_write_buffered_maintained_root_or_branch_page(pager, page_id, page);
}

static mylite_storage_result pager_write_buffered_maintained_root_or_branch_page(
    const mylite_storage_pager *pager,
    unsigned long long page_id,
    const unsigned char *page
) {
    int buffered = 0;
    mylite_storage_result result =
        buffer_dirty_page_for_pager_write(pager, page_id, page, &buffered);
    if (result != MYLITE_STORAGE_OK || buffered) {
        return result;
    }
    result = capture_dirty_page_undo_for_pager_write(pager, page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    result = write_page_at(pager->file, page_id, pager->header->page_size, page);
    if (result == MYLITE_STORAGE_OK) {
        store_active_index_leaf_page_from_pager_write(pager, page_id, page);
        store_active_index_branch_page_from_pager_write(pager, page_id, page);
        discard_dirty_page_buffer_entry_in_statement_chain(
            active_statement_for_file(pager->file),
            page_id
        );
    }
    return result;
}

static mylite_storage_result buffer_dirty_page_for_pager_write(
    const mylite_storage_pager *pager,
    unsigned long long page_id,
    const unsigned char *page,
    int *out_buffered
) {
    *out_buffered = 0;
    if (pager == NULL || pager->file == NULL || pager->header == NULL ||
        pager->header->page_size != MYLITE_STORAGE_FORMAT_PAGE_SIZE ||
        page_id == MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_statement *statement = active_statement_for_file(pager->file);
    if (statement == NULL || page_id >= statement->header.page_count) {
        return MYLITE_STORAGE_OK;
    }
    if (buffered_append_page(pager->file, page_id, pager->header->page_size) != NULL) {
        return MYLITE_STORAGE_OK;
    }
    if (!dirty_page_write_is_maintained_root_or_branch_page(page)) {
        return MYLITE_STORAGE_OK;
    }

    if (!dirty_page_undo_exists(&statement->dirty_page_undos, page_id) &&
        !dirty_page_buffer_exists_in_statement_chain(statement->parent, page_id)) {
        mylite_storage_result result = capture_dirty_page_undo_for_pager_write(pager, page_id);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    mylite_storage_result result = store_dirty_page_in_buffer(statement, page_id, page);
    if (result == MYLITE_STORAGE_OK) {
        store_active_index_branch_page_from_pager_write(pager, page_id, page);
        *out_buffered = 1;
    }
    return result;
}

static int dirty_page_write_is_maintained_root_or_branch_page(const unsigned char *page) {
    if (page == NULL || memcmp(
                            page + MYLITE_STORAGE_FORMAT_INDEX_MAGIC_OFFSET,
                            k_index_magic,
                            sizeof(k_index_magic)
                        ) != 0) {
        return 0;
    }

    const unsigned page_type = get_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_OFFSET);
    return page_type == MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_TABLE_INDEX_ROOT ||
           page_type == MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_TABLE_INDEX_BRANCH;
}

static mylite_storage_result capture_dirty_page_undo_for_pager_write(
    const mylite_storage_pager *pager,
    unsigned long long page_id
) {
    if (pager == NULL || pager->file == NULL || pager->header == NULL ||
        pager->header->page_size != MYLITE_STORAGE_FORMAT_PAGE_SIZE ||
        page_id == MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_statement *statement = active_statement_for_file(pager->file);
    if (statement == NULL || page_id >= statement->header.page_count ||
        dirty_page_undo_exists(&statement->dirty_page_undos, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (buffered_append_page(pager->file, page_id, pager->header->page_size) != NULL) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_result result = ensure_dirty_page_recovery_journal(pager, statement, page_id);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    result = read_page_at(pager->file, page_id, pager->header->page_size, page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    return append_dirty_page_undo(&statement->dirty_page_undos, page_id, page);
}

static mylite_storage_result ensure_dirty_page_recovery_journal(
    const mylite_storage_pager *pager,
    mylite_storage_statement *statement,
    unsigned long long page_id
) {
    if (journal_dirty_page_exists_in_statement_chain(statement, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (dirty_page_undo_exists_in_statement_chain(statement, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (statement_chain_has_transaction_journal(statement)) {
        return ensure_transaction_journal_protects_pages(pager, statement, &page_id, 1U);
    }
    if (statement_chain_has_write_journal(statement)) {
        return ensure_recovery_journal_protects_pages(pager, statement, &page_id, 1U);
    }
    if (statement->parent != NULL || pager->filename == NULL || pager->filename[0] == '\0') {
        return MYLITE_STORAGE_UNSUPPORTED;
    }

    mylite_storage_result result = begin_recovery_journal_for_pages(
        pager->file,
        pager->filename,
        pager->header,
        1,
        pager->header->free_list_root_page != 0ULL,
        &page_id,
        1U
    );
    if (result == MYLITE_STORAGE_OK) {
        statement->owns_recovery_journal = 1;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = append_journal_dirty_page_id(&statement->journal_dirty_pages, page_id);
    }
    return result;
}

static int dirty_page_undo_exists_in_statement_chain(
    const mylite_storage_statement *statement,
    unsigned long long page_id
) {
    for (const mylite_storage_statement *current = statement; current != NULL;
         current = current->parent) {
        if (dirty_page_undo_exists(&current->dirty_page_undos, page_id)) {
            return 1;
        }
    }
    return 0;
}

static int dirty_page_buffer_exists_in_statement_chain(
    const mylite_storage_statement *statement,
    unsigned long long page_id
) {
    for (const mylite_storage_statement *current = statement; current != NULL;
         current = current->parent) {
        if (const_dirty_page_buffer_entry(&current->dirty_pages, page_id) != NULL) {
            return 1;
        }
    }
    return 0;
}

static mylite_storage_result append_dirty_page_undo(
    mylite_storage_dirty_page_undo_list *undos,
    unsigned long long page_id,
    const unsigned char *page
) {
    if (undos->count == undos->capacity) {
        const size_t next_capacity = undos->capacity == 0U
                                         ? MYLITE_STORAGE_DIRTY_PAGE_UNDO_INITIAL_CAPACITY
                                         : undos->capacity * 2U;
        if (next_capacity <= undos->capacity ||
            next_capacity > SIZE_MAX / sizeof(*undos->entries)) {
            return MYLITE_STORAGE_FULL;
        }
        mylite_storage_dirty_page_undo *entries = (mylite_storage_dirty_page_undo *)
            realloc(undos->entries, next_capacity * sizeof(*undos->entries));
        if (entries == NULL) {
            return MYLITE_STORAGE_NOMEM;
        }
        undos->entries = entries;
        undos->capacity = next_capacity;
    }

    mylite_storage_dirty_page_undo *undo = undos->entries + undos->count;
    undo->page_id = page_id;
    memcpy(undo->page, page, MYLITE_STORAGE_FORMAT_PAGE_SIZE);
    ++undos->count;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_journal_dirty_page_id(
    mylite_storage_page_id_list *pages,
    unsigned long long page_id
) {
    if (journal_dirty_page_exists(pages, page_id)) {
        return MYLITE_STORAGE_OK;
    }
    if (pages->count == pages->capacity) {
        const size_t next_capacity = pages->capacity == 0U
                                         ? MYLITE_STORAGE_DIRTY_PAGE_UNDO_INITIAL_CAPACITY
                                         : pages->capacity * 2U;
        if (next_capacity <= pages->capacity ||
            next_capacity > SIZE_MAX / sizeof(*pages->entries)) {
            return MYLITE_STORAGE_FULL;
        }
        unsigned long long *entries =
            (unsigned long long *)realloc(pages->entries, next_capacity * sizeof(*pages->entries));
        if (entries == NULL) {
            return MYLITE_STORAGE_NOMEM;
        }
        pages->entries = entries;
        pages->capacity = next_capacity;
    }

    pages->entries[pages->count++] = page_id;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_journal_dirty_page_ids(
    mylite_storage_page_id_list *pages,
    const unsigned long long *page_ids,
    size_t page_count
) {
    for (size_t i = 0U; i < page_count; ++i) {
        if (page_ids == NULL) {
            return MYLITE_STORAGE_MISUSE;
        }
        const mylite_storage_result result = append_journal_dirty_page_id(pages, page_ids[i]);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static int dirty_page_undo_exists(
    const mylite_storage_dirty_page_undo_list *undos,
    unsigned long long page_id
) {
    if (undos == NULL) {
        return 0;
    }

    for (size_t i = 0U; i < undos->count; ++i) {
        if (undos->entries[i].page_id == page_id) {
            return 1;
        }
    }
    return 0;
}

static int journal_dirty_page_exists(
    const mylite_storage_page_id_list *pages,
    unsigned long long page_id
) {
    if (pages == NULL) {
        return 0;
    }

    for (size_t i = 0U; i < pages->count; ++i) {
        if (pages->entries[i] == page_id) {
            return 1;
        }
    }
    return 0;
}

static int journal_dirty_page_exists_in_statement_chain(
    const mylite_storage_statement *statement,
    unsigned long long page_id
) {
    for (const mylite_storage_statement *current = statement; current != NULL;
         current = current->parent) {
        if (journal_dirty_page_exists(&current->journal_dirty_pages, page_id)) {
            return 1;
        }
    }
    return 0;
}

