int mylite_storage_test_branch_tail_overlay_cache_uses_root_owner(void) {
    FILE *file = tmpfile();
    if (file == NULL) {
        return 0;
    }

    int owner = 0;
    const void *saved_owner = active_context_owner;
    mylite_storage_statement *saved_active_statement = active_statement;
    mylite_storage_statement parent = {
        .file = file,
        .owner = &owner,
    };
    mylite_storage_statement child = {
        .file = file,
        .parent = &parent,
        .owner = &owner,
    };

    active_context_owner = &owner;
    active_statement = &child;
    const int uses_root = branch_tail_overlay_cache_statement_for_file(file) == &parent;
    active_statement = saved_active_statement;
    active_context_owner = saved_owner;

    fclose(file);
    return uses_root ? 1 : 0;
}

int mylite_storage_test_branch_tail_overlay_cache_retains_after_limit(void) {
    mylite_storage_statement statement = {0};
    unsigned char branch_payload[MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + 1U] = {0};
    mylite_storage_index_branch_page branch_page = {
        .level = 1U,
        .key_size = 1U,
        .child_count = 1U,
        .payload = branch_payload,
    };

    const size_t inserted_count = MYLITE_STORAGE_BRANCH_TAIL_OVERLAY_CACHE_LIMIT + 3U;
    for (size_t i = 0U; i < inserted_count; ++i) {
        store_branch_tail_overlay_cache(
            &statement,
            1ULL,
            (unsigned)i,
            &branch_page,
            (unsigned long long)i + 1ULL,
            (unsigned long long)i + 10ULL,
            0,
            0ULL
        );
    }

    mylite_storage_branch_tail_overlay_cache_set *caches = &statement.branch_tail_overlay_caches;
    int retained = caches->count == MYLITE_STORAGE_BRANCH_TAIL_OVERLAY_CACHE_LIMIT &&
                   find_branch_tail_overlay_cache(&statement, 1ULL, 0U, &branch_page, 1ULL) == NULL;

    mylite_storage_branch_tail_overlay_cache *oldest_retained =
        find_branch_tail_overlay_cache(&statement, 1ULL, 3U, &branch_page, 4ULL);
    retained = retained && oldest_retained != NULL && oldest_retained->scanned_page_count == 13ULL;

    const unsigned latest_index = (unsigned)(inserted_count - 1U);
    mylite_storage_branch_tail_overlay_cache *latest_retained = find_branch_tail_overlay_cache(
        &statement,
        1ULL,
        latest_index,
        &branch_page,
        (unsigned long long)inserted_count
    );
    retained = retained && latest_retained != NULL &&
               latest_retained->scanned_page_count == (unsigned long long)inserted_count + 9ULL;

    clear_branch_tail_overlay_caches(&statement);
    return retained ? 1 : 0;
}

int mylite_storage_test_branch_refold_entryset_cache_roundtrip(void) {
    FILE *file = tmpfile();
    if (file == NULL) {
        return 0;
    }

    int owner = 0;
    int ok = 0;
    int used_cache = 0;
    const void *saved_owner = active_context_owner;
    mylite_storage_statement *saved_active_statement = active_statement;
    unsigned char first_key[] = {0x01U, 0x10U};
    unsigned char second_key[] = {0x02U, 0x20U};
    unsigned char third_key[] = {0x03U, 0x30U};
    mylite_storage_index_entryset entryset = {
        .size = sizeof(entryset),
    };
    mylite_storage_index_entryset cached = {
        .size = sizeof(cached),
    };
    mylite_storage_index_entry index_entry = {
        .size = sizeof(index_entry),
        .index_number = 3U,
        .key = first_key,
        .key_size = sizeof(first_key),
    };
    mylite_storage_index_branch_page branch_page = {
        .table_id = 44ULL,
        .entry_count = 2ULL,
        .index_number = 3U,
        .level = 1U,
        .key_size = sizeof(first_key),
    };
    mylite_storage_statement parent = {
        .file = file,
        .owner = &owner,
    };
    mylite_storage_statement child = {
        .file = file,
        .parent = &parent,
        .owner = &owner,
    };

    active_context_owner = &owner;
    active_statement = &child;
    mylite_storage_statement *cache_statement =
        branch_refold_entryset_cache_statement_for_file(file);
    if (cache_statement != &parent) {
        goto cleanup;
    }
    if (append_raw_index_entry_to_entryset(&entryset, 11ULL, &index_entry) != MYLITE_STORAGE_OK) {
        goto cleanup;
    }
    index_entry.key = second_key;
    if (append_raw_index_entry_to_entryset(&entryset, 22ULL, &index_entry) != MYLITE_STORAGE_OK) {
        goto cleanup;
    }

    test_branch_refold_entryset_cache_hit_count = 0ULL;
    store_branch_refold_entryset_cache(cache_statement, 77ULL, 44ULL, &index_entry, &entryset);
    if (parent.branch_refold_entryset_cache.count != 1U) {
        goto cleanup;
    }
    if (copy_active_branch_refold_entryset_for_insert(
            file,
            77ULL,
            44ULL,
            &branch_page,
            &index_entry,
            &cached,
            &used_cache
        ) != MYLITE_STORAGE_OK ||
        !used_cache || cached.entry_count != 2U || cached.row_ids[0] != 11ULL ||
        cached.row_ids[1] != 22ULL ||
        memcmp(cached.keys + cached.key_offsets[0], first_key, sizeof(first_key)) != 0 ||
        memcmp(cached.keys + cached.key_offsets[1], second_key, sizeof(second_key)) != 0) {
        goto cleanup;
    }
    if (test_branch_refold_entryset_cache_hit_count != 1ULL) {
        goto cleanup;
    }

    mylite_storage_free_index_entryset(&cached);
    cached = (mylite_storage_index_entryset){
        .size = sizeof(cached),
    };
    index_entry.key = third_key;
    mylite_storage_maintained_index_insert_plan plan = {
        .branch_count = 1U,
        .branch_entries = {
            {
                .entry_index = 0U,
                .root_page_id = 77ULL,
                .leaf_page_id = 88ULL,
            },
        },
    };
    update_branch_refold_entryset_caches_after_branch_insert(
        cache_statement,
        44ULL,
        33ULL,
        &index_entry,
        1U,
        &plan
    );
    branch_page.entry_count = 3ULL;
    used_cache = 0;
    if (copy_active_branch_refold_entryset_for_insert(
            file,
            77ULL,
            44ULL,
            &branch_page,
            &index_entry,
            &cached,
            &used_cache
        ) != MYLITE_STORAGE_OK ||
        !used_cache || cached.entry_count != 3U || cached.row_ids[0] != 11ULL ||
        cached.row_ids[1] != 22ULL || cached.row_ids[2] != 33ULL ||
        memcmp(cached.keys + cached.key_offsets[2], third_key, sizeof(third_key)) != 0) {
        goto cleanup;
    }
    if (test_branch_refold_entryset_cache_hit_count != 2ULL) {
        goto cleanup;
    }

    mylite_storage_free_index_entryset(&cached);
    cached = (mylite_storage_index_entryset){
        .size = sizeof(cached),
    };
    branch_page.entry_count = 4ULL;
    used_cache = 0;
    if (copy_active_branch_refold_entryset_for_insert(
            file,
            77ULL,
            44ULL,
            &branch_page,
            &index_entry,
            &cached,
            &used_cache
        ) != MYLITE_STORAGE_OK ||
        used_cache) {
        goto cleanup;
    }
    branch_page.entry_count = 3ULL;
    remove_branch_refold_entryset_caches_for_table(cache_statement, 44ULL);
    if (copy_active_branch_refold_entryset_for_insert(
            file,
            77ULL,
            44ULL,
            &branch_page,
            &index_entry,
            &cached,
            &used_cache
        ) != MYLITE_STORAGE_OK ||
        used_cache) {
        goto cleanup;
    }
    ok = 1;

cleanup:
    mylite_storage_free_index_entryset(&cached);
    mylite_storage_free_index_entryset(&entryset);
    clear_branch_refold_entryset_cache(&parent);
    active_statement = saved_active_statement;
    active_context_owner = saved_owner;
    fclose(file);
    return ok;
}

