mylite_storage_result mylite_storage_test_encode_index_leaf_page(
    unsigned char *page,
    unsigned long long page_id,
    unsigned long long table_id,
    unsigned index_number,
    size_t key_size,
    const unsigned long long *row_ids,
    const unsigned char *keys,
    size_t entry_count
) {
    if (page == NULL || (entry_count != 0U && (row_ids == NULL || keys == NULL))) {
        return MYLITE_STORAGE_MISUSE;
    }
    if (key_size > UINT32_MAX || entry_count > UINT32_MAX) {
        return MYLITE_STORAGE_FULL;
    }
    const size_t entry_capacity = index_leaf_entry_capacity(key_size);
    if (entry_count == 0U || entry_count > entry_capacity) {
        return MYLITE_STORAGE_CORRUPT;
    }
    const size_t cell_size = MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE + key_size;
    if (entry_count >
        (MYLITE_STORAGE_FORMAT_PAGE_SIZE - MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET) /
            cell_size) {
        return MYLITE_STORAGE_FULL;
    }

    const size_t used_bytes =
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET + (entry_count * cell_size);
    memset(page, 0, MYLITE_STORAGE_FORMAT_PAGE_SIZE);
    memcpy(page + MYLITE_STORAGE_FORMAT_INDEX_MAGIC_OFFSET, k_index_magic, sizeof(k_index_magic));
    put_u32_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_OFFSET,
        MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_TABLE_INDEX_LEAF
    );
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_PAGE_VERSION_OFFSET, 1U);
    put_u32_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_FORMAT_VERSION_OFFSET,
        MYLITE_STORAGE_FORMAT_VERSION
    );
    put_u32_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_CHECKSUM_ALGORITHM_OFFSET,
        MYLITE_STORAGE_FORMAT_CHECKSUM_FNV1A64
    );
    put_u64_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAGE_ID_OFFSET, page_id);
    put_u64_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_TABLE_ID_OFFSET, table_id);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_INDEX_NUMBER_OFFSET, index_number);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_KEY_SIZE_OFFSET, (unsigned)key_size);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_COUNT_OFFSET, (unsigned)entry_count);
    put_u32_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_USED_BYTES_OFFSET, (unsigned)used_bytes);
    for (size_t i = 0U; i < entry_count; ++i) {
        unsigned char *cell =
            page + MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET + (i * cell_size);
        put_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET, row_ids[i]);
        memcpy(
            cell + MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET,
            keys + (i * key_size),
            key_size
        );
    }
    put_u64_le(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET, 0ULL);
    put_u64_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET,
        checksum_page_zero_tail(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET, used_bytes)
    );
    return MYLITE_STORAGE_OK;
}

int mylite_storage_test_prepare_index_leaf_pages_identity_order(void) {
    mylite_storage_index_entryset sorted_entries = {
        .size = sizeof(sorted_entries),
    };
    mylite_storage_index_entryset unsorted_entries = {
        .size = sizeof(unsorted_entries),
    };
    unsigned char *pages = NULL;
    size_t page_count = 0U;
    int ok = 0;

    unsigned char sorted_keys[] = {0x01U, 0x01U, 0x02U};
    const unsigned long long sorted_row_ids[] = {10ULL, 11ULL, 20ULL};
    mylite_storage_index_entry entry = {
        .size = sizeof(entry),
        .index_number = 0U,
        .key_size = 1U,
    };
    for (size_t i = 0U; i < 3U; ++i) {
        entry.key = sorted_keys + i;
        if (append_raw_index_entry_to_entryset(&sorted_entries, sorted_row_ids[i], &entry) !=
            MYLITE_STORAGE_OK) {
            goto cleanup;
        }
    }

    test_raw_index_entry_order_build_count = 0ULL;
    if (prepare_index_leaf_pages(&pages, &page_count, 7ULL, 3ULL, 0U, &sorted_entries) !=
            MYLITE_STORAGE_OK ||
        page_count != 1U || test_raw_index_entry_order_build_count != 0ULL) {
        goto cleanup;
    }
    const size_t cell_size = MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_HEADER_SIZE + 1U;
    const unsigned char *payload = pages + MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET;
    if (get_u32_le(pages, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_COUNT_OFFSET) != 3U ||
        get_u64_le(payload, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET) != 10ULL ||
        payload[MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET] != 0x01U ||
        get_u64_le(payload + cell_size, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET) !=
            11ULL ||
        payload[cell_size + MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET] != 0x01U ||
        get_u64_le(
            payload + (2U * cell_size),
            MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET
        ) != 20ULL ||
        payload[(2U * cell_size) + MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET] != 0x02U) {
        goto cleanup;
    }

    free(pages);
    pages = NULL;
    page_count = 0U;

    unsigned char unsorted_keys[] = {0x02U, 0x01U, 0x01U};
    const unsigned long long unsorted_row_ids[] = {20ULL, 11ULL, 10ULL};
    for (size_t i = 0U; i < 3U; ++i) {
        entry.key = unsorted_keys + i;
        if (append_raw_index_entry_to_entryset(&unsorted_entries, unsorted_row_ids[i], &entry) !=
            MYLITE_STORAGE_OK) {
            goto cleanup;
        }
    }

    test_raw_index_entry_order_build_count = 0ULL;
    if (prepare_index_leaf_pages(&pages, &page_count, 8ULL, 3ULL, 0U, &unsorted_entries) !=
            MYLITE_STORAGE_OK ||
        page_count != 1U || test_raw_index_entry_order_build_count != 1ULL) {
        goto cleanup;
    }
    payload = pages + MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET;
    if (get_u32_le(pages, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_COUNT_OFFSET) != 3U ||
        get_u64_le(payload, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET) != 10ULL ||
        payload[MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET] != 0x01U ||
        get_u64_le(payload + cell_size, MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET) !=
            11ULL ||
        payload[cell_size + MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET] != 0x01U ||
        get_u64_le(
            payload + (2U * cell_size),
            MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_ROW_ID_OFFSET
        ) != 20ULL ||
        payload[(2U * cell_size) + MYLITE_STORAGE_FORMAT_INDEX_LEAF_ENTRY_KEY_OFFSET] != 0x02U) {
        goto cleanup;
    }

    ok = 1;

cleanup:
    free(pages);
    mylite_storage_free_index_entryset(&unsorted_entries);
    mylite_storage_free_index_entryset(&sorted_entries);
    return ok;
}

